    name: "Sismo Modal — MATLAB",
    code: `# Analisis Sismico Modal — 2 Pisos
> Norma Peru E.030 — Sintaxis MATLAB

## 1. Datos
> Peso por piso (tonf)
WD = 9
WL = 0.9
W_piso = WD + WL
W_total = 2 * W_piso
> Masa: m = W/g
g_val = 9.8
m_val = W_piso / g_val

## 2. Matrices MATLAB
> Rigidez lateral KL (tonf/m)
K = [1243.5, -492.6; -492.6, 317.9]
> Masa (tonf*s^2/m)
M = [m_val, 0; 0, m_val]

## 3. Valores propios
A = inv(M) * K
w2 = eigenvalues(A)
w2_1 = w2[1]
w2_2 = w2[2]

## 4. Frecuencias y periodos
omega_1 = sqrt(w2_1)
omega_2 = sqrt(w2_2)
T_1 = 2*pi/omega_1
T_2 = 2*pi/omega_2

## 5. Modos de vibracion
> (A - lambda*I)*phi = 0
a11 = A[1,1]
a12 = A[1,2]
> Modo 1
r1 = (a11 - w2_1)/(-a12)
phi_11 = -1/sqrt(1 + r1^2)
phi_21 = r1 * phi_11
> Modo 2
r2 = (a11 - w2_2)/(-a12)
phi_12 = -1/sqrt(1 + r2^2)
phi_22 = r2 * phi_12

## 6. Participacion modal
> gamma = phi^T*M*b / (phi^T*M*phi)
gamma_1 = (phi_11 + phi_21) / (phi_11^2 + phi_21^2)
gamma_2 = (phi_12 + phi_22) / (phi_12^2 + phi_22^2)

## 7. Espectro NTP E.030
> C = min(2.5*S, 1.25*S^S/T)
S_s = 1.2
Ss = S_s^S_s
C_max = 2.5 * S_s
C_1 = min(C_max, 1.25*Ss/T_1)
C_2 = min(C_max, 1.25*Ss/T_2)
> Sa = Z*C/R * g
Z = 0.4
R_s = 6
Sa_1 = Z * C_1 / R_s * g_val
Sa_2 = Z * C_2 / R_s * g_val

## 8. Fuerzas por modo (tonf)
> F = gamma * Sa * m * phi
F_11 = gamma_1 * Sa_1 * m_val * phi_11
F_21 = gamma_1 * Sa_1 * m_val * phi_21
V_b1 = abs(F_11 + F_21)
F_12 = gamma_2 * Sa_2 * m_val * phi_12
F_22 = gamma_2 * Sa_2 * m_val * phi_22
V_b2 = abs(F_12 + F_22)

## 9. Combinacion NTP
> V = 0.25*sum|Vi| + 0.75*sqrt(sum Vi^2)
V_base = 0.25*(V_b1 + V_b2) + 0.75*sqrt(V_b1^2 + V_b2^2)
S2_1 = abs(F_21)
S2_2 = abs(F_22)
V_2 = 0.25*(S2_1 + S2_2) + 0.75*sqrt(S2_1^2 + S2_2^2)
> Fuerzas por piso
F_piso2 = V_2
F_piso1 = V_base - V_2

## 10. Cortante basal minimo
V_min = Z * C_1 / R_s * W_total
> V_base >= V_min?
check = V_base - V_min`,
