// ─── Evaluator ──────────────────────────────────────────
const evaluator = new HekatanEvaluator();
(window as any)._hkEval = evaluator; // debug: expose evaluator

// Track active 3D scenes for cleanup
let active3DScenes: Draw3DScene[] = [];

async function runCode() {
  const code = codeInput.value;
  if (!code.trim()) { output.innerHTML = `<div class="output-pages-wrapper"><div class="output-page"></div></div>`; return; }

  // Reset render config to defaults (checkbox state overrides for frac)
  resetRenderCfg();
  renderCfg.frac = chkFractions.checked;
  setFractions(renderCfg.frac);

  // Cleanup previous 3D scenes
  for (const sc of active3DScenes) sc.dispose();
  active3DScenes = [];

  // Prepend function library (virtual directory) — functions are silent (no output)
  const fnLibPrefix = getFnLibCode();
  const fullCode = fnLibPrefix + code;

  try {
    const results = await evaluator.evalDocument(fullCode);
    // Strip library results by finding the sentinel marker
    if (fnLibPrefix) {
      const endIdx = results.findIndex(r =>
        r.input?.includes("__FNLIB_END__")
      );
      if (endIdx >= 0) {
        // Calculate line offset from fnLib prefix so remaining results have correct lineIndex
        const fnLibLineCount = fnLibPrefix.split("\n").length - 1;
        results.splice(0, endIdx + 1);
        // Adjust lineIndex of remaining results to match user's code (without prefix)
        for (const r of results) {
          if (r.lineIndex != null) r.lineIndex -= fnLibLineCount;
        }
      }
    }
    // Apply @{config matvis:N} if set, otherwise use UI selector
    if (evaluator.matVisSize >= 0) {
      _matVisSize = evaluator.matVisSize;
      matVisSelect.value = evaluator.matVisSize === 0 ? "0" : String(evaluator.matVisSize);
    }
    const rawHTML = renderResults(results, code);
    // Split by page break markers into multiple pages
    const pageContents = rawHTML.split("<!--PAGEBREAK-->");
    // Apply page background color from @{config bg:...}
    const bgColorMap: Record<string, string> = {
      // Papeles y neutros
      white: "#ffffff", cream: "#fdf6e3", ivory: "#fffff0",
      paper: "#f5f0e8", parchment: "#f4e8c1", linen: "#faf0e6",
      snow: "#fffafa", seashell: "#fff5ee", oldpaper: "#e8dcc8", antique: "#faebd7",
      // Grises
      light: "#f8f8f8", silver: "#f0f0f0", gray: "#e8e8e8", grey: "#e8e8e8", smoke: "#f5f5f5",
      // Calidos
      sand: "#f5e6ca", peach: "#ffdab9", wheat: "#f5deb3", beige: "#f5f5dc", honey: "#f0e68c",
      sepia: "#f4ecd8",
      // Frios
      ice: "#f0f8ff", sky: "#e6f2ff", mint: "#f0fff0", lavender: "#f0e6ff", pearl: "#eae8e5",
      // Libros / textbook
      book: "#f0eae4", bookwarm: "#f2eced", textbook: "#ede6df", notebook: "#f7f2ec",
      // Ingenieria
      blueprint: "#e8eef7", grid: "#f0f4e8", graph: "#f8f8f0",
      // Oscuros
      black: "#1a1a2e", dark: "#1a1a2e", night: "#0d1117", midnight: "#191970",
      charcoal: "#2c2c2c", slate: "#2f3640",
    };
    const rawBg = evaluator.pageBackground || "";
    const pageBg = bgColorMap[rawBg.toLowerCase()] || rawBg || "";
    const bgStyle = pageBg ? ` style="background-color:${pageBg}"` : "";
    // Build eq-black class if color:black is set
    const eqBlackClass = evaluator.eqBlack ? " eq-black" : "";
    const pagesHTML = pageContents.map((pc, idx) => {
      // Page header with page number if header:on
      let headerHtml = "";
      let footerHtml = "";
      if (evaluator.pageHeader && idx > 0) {
        const pageNum = evaluator.startPage + idx;
        const title = evaluator.headerTitle || "";
        headerHtml = `<div class="page-header"><div class="header-content"><span class="header-section">${escHtml(title)}</span><span class="header-pagenum">${pageNum}</span></div><hr class="header-rule"></div>`;
      }
      if (evaluator.pageFooter) {
        const pageNum = evaluator.startPage + idx;
        footerHtml = `<div class="page-footer"><hr class="footer-rule"><div class="footer-content"><span class="footer-section"></span><span class="footer-pagenum">${pageNum}</span></div></div>`;
      }
      return `<div class="output-page${eqBlackClass}"${bgStyle}>${headerHtml}${pc}${footerHtml}</div>`;
    }).join("\n");
    output.innerHTML = `<div class="output-pages-wrapper">${pagesHTML}</div>`;
    // Render @{draw} CAD blocks into their canvas elements (must be after innerHTML)
    renderDrawBlocks(results, pageBg);
    // Build figure navigation bar
    buildFigNav();
    // Render @{three} Three.js scenes (using local THREE module)
    renderThreeBlocks(results);
    // Render @{draw:3D} Three.js blocks
    renderDraw3DBlocks(results);
    // Render @{draw:3D:IFC} file upload + viewer
    renderDraw3DIfcBlocks(results);
    // Render @{import:ifc:file} auto-load IFC models
    renderImportIfcBlocks(results);
    // Fix expression layout (centering + overlap), then page-break + zoom
    setTimeout(() => { fixExpressionLayout(); autoPageBreak(); syncZoom(); }, 50);
  } catch (e: any) {
    output.innerHTML = `<div class="output-pages-wrapper"><div class="output-page"><div class="out-error">Error: ${escHtml(e.message)}</div></div></div>`;
    setTimeout(syncZoom, 50);
  }
}

// ─── Figure Zoom Overlay ─────────────────────────────────
function openFigZoom(figNum: number) {
  const data = _figData.get(figNum);
  if (!data) return;

  // Remove any existing overlay
  document.getElementById("fig-zoom-overlay")?.remove();

  // Compute scaled canvas size: fit to 90% of viewport
  const vw = window.innerWidth * 0.9;
  const vh = window.innerHeight * 0.88;
  const scaleX = vw / data.w;
  const scaleY = vh / data.h;
  const scale = Math.min(scaleX, scaleY, 4);  // cap at 4x
  const cw = Math.round(data.w * scale);
  const ch = Math.round(data.h * scale);

  const overlay = document.createElement("div");
  overlay.id = "fig-zoom-overlay";
  overlay.style.cssText = `position:fixed;inset:0;z-index:99999;background:rgba(0,0,0,0.82);display:flex;flex-direction:column;align-items:center;justify-content:center;cursor:pointer;`;
  overlay.addEventListener("click", (e) => {
    if (e.target === overlay || (e.target as HTMLElement).classList.contains("fig-zoom-close")) overlay.remove();
  });

  // Header
  const header = document.createElement("div");
  const label = data.name ? `Fig. ${figNum}  ${data.name}` : `Fig. ${figNum}`;
  header.style.cssText = `color:#fff;font-size:16px;font-family:'Segoe UI',sans-serif;margin-bottom:8px;display:flex;align-items:center;gap:16px;`;
  header.innerHTML = `<span style="font-weight:600;">${label}</span><span style="font-size:12px;color:#aaa;">${data.w}×${data.h} → ${cw}×${ch} (${scale.toFixed(1)}x)</span><button class="fig-zoom-close" style="margin-left:auto;background:#555;color:#fff;border:none;border-radius:4px;padding:4px 14px;cursor:pointer;font-size:13px;">✕ Cerrar</button>`;
  overlay.appendChild(header);

  // Canvas
  const canvas = document.createElement("canvas");
  canvas.width = cw;
  canvas.height = ch;
  canvas.style.cssText = `border:2px solid #666;border-radius:4px;background:#fff;cursor:default;max-width:90vw;max-height:85vh;`;
  canvas.addEventListener("click", (e) => e.stopPropagation());
  overlay.appendChild(canvas);

  // Navigation arrows
  const nav = document.createElement("div");
  nav.style.cssText = `display:flex;gap:12px;margin-top:8px;`;
  const totalFigs = _figData.size;
  if (totalFigs > 1) {
    const prevNum = figNum > 1 ? figNum - 1 : totalFigs;
    const nextNum = figNum < totalFigs ? figNum + 1 : 1;
    const btnStyle = `background:#555;color:#fff;border:none;border-radius:4px;padding:6px 16px;cursor:pointer;font-size:13px;`;
    nav.innerHTML = `<button style="${btnStyle}" onclick="event.stopPropagation();document.getElementById('fig-zoom-overlay').remove();window._hkFigZoom(${prevNum})">◀ Fig. ${prevNum}</button><span style="color:#888;font-size:12px;align-self:center;">${figNum} / ${totalFigs}</span><button style="${btnStyle}" onclick="event.stopPropagation();document.getElementById('fig-zoom-overlay').remove();window._hkFigZoom(${nextNum})">Fig. ${nextNum} ▶</button>`;
  }
  overlay.appendChild(nav);

  document.body.appendChild(overlay);

  // Render CAD using high-DPI approach:
  // Canvas pixel buffer = cw × ch, but logical coordinate space = original w × h
  // ctx.scale handles the upscaling so all CAD coordinates work unchanged
  canvas.width = cw;
  canvas.height = ch;
  canvas.style.width = `${cw}px`;
  canvas.style.height = `${ch}px`;
  const ctx = canvas.getContext("2d");
  if (!ctx) return;
  ctx.scale(scale, scale);
  const eng = new CadEngine();
  eng.canvasW = data.w;
  eng.canvasH = data.h;
  execCommands(eng, data.commands.join("\n"));
  eng.zoomFit();
  eng.renderToCtx(ctx, data.w, data.h);

  // ESC to close
  const onKey = (e: KeyboardEvent) => {
    if (e.key === "Escape") { overlay.remove(); window.removeEventListener("keydown", onKey); }
    if (e.key === "ArrowLeft" && totalFigs > 1) {
      const prev = figNum > 1 ? figNum - 1 : totalFigs;
      overlay.remove(); window.removeEventListener("keydown", onKey);
      openFigZoom(prev);
    }
    if (e.key === "ArrowRight" && totalFigs > 1) {
      const next = figNum < totalFigs ? figNum + 1 : 1;
      overlay.remove(); window.removeEventListener("keydown", onKey);
      openFigZoom(next);
    }
  };
  window.addEventListener("keydown", onKey);
}

// Expose globally for onclick handlers in generated HTML
(window as any)._hkFigZoom = openFigZoom;

// ─── Figure Navigation: scroll to fig(n) ─────────────────
function scrollToFig(figNum: number) {
  const el = document.getElementById(`fig-${figNum}`);
  if (el) {
    el.scrollIntoView({ behavior: "smooth", block: "center" });
    // Flash highlight
    el.style.outline = "3px solid #4488ff";
    el.style.outlineOffset = "4px";
    setTimeout(() => { el.style.outline = ""; el.style.outlineOffset = ""; }, 1500);
  }
}
(window as any)._hkFigNav = scrollToFig;

// ─── Build figure navigation bar after render ─────────────
function buildFigNav() {
  let bar = document.getElementById("figNavBar");
  if (_figCount === 0) { bar?.remove(); return; }

  if (!bar) {
    bar = document.createElement("div");
    bar.id = "figNavBar";
    // Insert at top of output panel
    const outputPanel = output.parentElement;
    if (outputPanel) outputPanel.insertBefore(bar, output);
  }

  const btns: string[] = [];
  for (let i = 1; i <= _figCount; i++) {
    const d = _figData.get(i);
    const label = d?.name ? `${i}: ${d.name}` : `${i}`;
    btns.push(`<button class="fig-nav-btn" onclick="window._hkFigNav(${i})" title="Ir a Figura ${i}">Fig ${label}</button>`);
  }
  bar.className = "fig-nav-bar";
  bar.innerHTML = `<span class="fig-nav-label">Figuras:</span>${btns.join("")}`;
}

// ─── Fix expression layout: dynamic centering + overlap detection ───
/**
 * After rendering, fix layout issues:
 * 1. mat-trunc grids with col-idx headers: add padding-bottom = col-idx row height
 *    to mat-trunc so that flex align-items:center on .out-line centers the = sign
 *    with the DATA area (brackets), not with the full grid including column indices.
 * 2. Unit label alignment: for mat-unit-sticky next to mat-trunc, align the unit's
 *    visual center (text center for simple units, fraction bar for fractions) with
 *    the bracket center using position:relative + top offset.
 * 3. Overlap detection: add margin-top to consecutive elements that overlap.
 */
function fixExpressionLayout() {
  const pages = output.querySelectorAll(".output-page");
  for (const page of pages) {
    // ── Reset all dynamic styles ──
    for (const mt of page.querySelectorAll<HTMLElement>(".mat-trunc")) {
      mt.style.removeProperty("padding-bottom");
    }
    for (const w of page.querySelectorAll<HTMLElement>(".mat-with-unit")) {
      w.style.removeProperty("padding-bottom");
    }
    for (const u of page.querySelectorAll<HTMLElement>(".mat-unit-sticky")) {
      u.style.removeProperty("padding-top");
      u.style.removeProperty("padding-bottom");
    }
    for (const el of page.querySelectorAll<HTMLElement>(".mat-unit-sticky .unit")) {
      el.style.removeProperty("position");
      el.style.removeProperty("top");
    }
    for (const el of page.querySelectorAll<HTMLElement>(".out-line, .out-comment, .out-empty, .chapter-heading, .section-heading, p.eq, h1, h2, h3, hr")) {
      el.style.removeProperty("margin-top");
    }

    // Force reflow after reset
    void page.offsetHeight;

    // ── Part 1: mat-trunc centering (padding-bottom on mat-trunc itself) ──
    // This makes the flex center of mat-trunc = center of data area (bracket center).
    // The bracket already covers only data rows via inline grid-row:2/-1.
    for (const mt of page.querySelectorAll<HTMLElement>(".mat-trunc")) {
      const colIdx = mt.querySelector<HTMLElement>(".mat-col-idx");
      if (!colIdx) continue;
      const colIdxRect = colIdx.getBoundingClientRect();
      const mtRect = mt.getBoundingClientRect();
      const colIdxH = colIdxRect.bottom - mtRect.top;
      if (colIdxH <= 0) continue;
      mt.style.paddingBottom = `${colIdxH}px`;
    }

    // Force reflow so bracket positions update
    void page.offsetHeight;

    // ── Part 2: Unit label alignment with bracket center ──
    // After mat-trunc padding, the = sign is centered with the bracket center.
    // Now align the unit label's visual center with the bracket center too.
    for (const wrapper of page.querySelectorAll<HTMLElement>(".mat-with-unit")) {
      const mt = wrapper.querySelector<HTMLElement>(".mat-trunc");
      const unitSticky = wrapper.querySelector<HTMLElement>(".mat-unit-sticky");
      if (!mt || !unitSticky) continue;

      const bracket = mt.querySelector<HTMLElement>(".mat-bracket");
      if (!bracket) continue;

      const bracketRect = bracket.getBoundingClientRect();
      const bracketMidY = (bracketRect.top + bracketRect.bottom) / 2;

      // Find the unit content element (<i class="unit">)
      const unitEl = unitSticky.querySelector<HTMLElement>(".unit");
      if (!unitEl) continue;

      // Determine the visual center of the unit:
      // - For fractions (.dvc with .dvl): the fraction bar (dvl border-bottom) = dvl bottom edge
      // - For non-fractions: the text vertical center
      const dvl = unitEl.querySelector<HTMLElement>(".dvl");
      let unitVisualY: number;
      if (dvl) {
        // Fraction: visual center = fraction bar = bottom edge of dvl
        const dvlRect = dvl.getBoundingClientRect();
        unitVisualY = dvlRect.bottom;
      } else {
        // Non-fraction: visual center = midpoint of the unit element
        const unitElRect = unitEl.getBoundingClientRect();
        unitVisualY = (unitElRect.top + unitElRect.bottom) / 2;
      }

      // Shift unit content to align visual center with bracket center
      const offset = bracketMidY - unitVisualY;
      if (Math.abs(offset) > 0.5) {
        unitEl.style.position = "relative";
        unitEl.style.top = `${offset}px`;
      }
    }

    // ── Part 3: Overlap detection between consecutive elements ──
    // Only fix VERTICAL overlap — skip elements that are side-by-side
    // (e.g. in a CSS grid/flex column layout from @{columns}).
    const lines = page.querySelectorAll<HTMLElement>(
      ".out-line, .out-comment, .out-empty, .chapter-heading, .section-heading, p.eq, h1, h2, h3, hr"
    );
    for (let i = 1; i < lines.length; i++) {
      const prev = lines[i - 1];
      const curr = lines[i];
      const prevRect = prev.getBoundingClientRect();
      const currRect = curr.getBoundingClientRect();
      // Skip if elements are side-by-side (no horizontal overlap) — grid/flex columns
      if (prevRect.right <= currRect.left || currRect.right <= prevRect.left) continue;
      const overlap = prevRect.bottom - currRect.top;
      if (overlap > 1) {
        const existingMargin = parseFloat(getComputedStyle(curr).marginTop) || 0;
        curr.style.marginTop = `${existingMargin + overlap + 2}px`;
      }
    }
  }
}

// ─── Auto page-break: split pages when content overflows A4 height ───
function autoPageBreak() {
  const wrapper = output.querySelector(".output-pages-wrapper") as HTMLElement;
  if (!wrapper) return;

  // Measure 267mm (A4 297mm - 15mm top padding - 15mm bottom padding) in pixels
  const probe = document.createElement("div");
  probe.style.cssText = "position:absolute;visibility:hidden;height:267mm;";
  document.body.appendChild(probe);
  const maxContentPx = probe.offsetHeight;
  document.body.removeChild(probe);

  let safety = 50; // prevent infinite loop
  while (safety-- > 0) {
    const pages = Array.from(wrapper.querySelectorAll(".output-page")) as HTMLElement[];
    let didSplit = false;

    for (const page of pages) {
      const children = Array.from(page.children) as HTMLElement[];
      if (children.length <= 1) continue; // single element — can't split further

      // offsetTop includes padding-top, so max = padTop + contentHeight
      const padTop = parseFloat(getComputedStyle(page).paddingTop) || 0;
      const maxBottomPx = padTop + maxContentPx;

      let splitIdx = -1;
      for (let i = 0; i < children.length; i++) {
        // offsetTop is relative to .output-page (position:relative)
        const bottom = children[i].offsetTop + children[i].offsetHeight;
        if (bottom > maxBottomPx && i > 0) {
          splitIdx = i;
          break;
        }
      }

      if (splitIdx > 0) {
        const newPage = document.createElement("div");
        newPage.className = page.className; // Inherit eq-black class too
        // Inherit page background from first page
        if (page.style.backgroundColor) newPage.style.backgroundColor = page.style.backgroundColor;
        // Skip page-header and page-footer children when splitting
        const contentChildren = children.filter(c => !c.classList.contains("page-header") && !c.classList.contains("page-footer"));
        const actualSplit = contentChildren[splitIdx] ? splitIdx : splitIdx;
        const toMove = children.filter(c =>
          !c.classList.contains("page-header") &&
          !c.classList.contains("page-footer") &&
          children.indexOf(c) >= splitIdx
        );
        for (const el of toMove) newPage.appendChild(el);
        wrapper.insertBefore(newPage, page.nextSibling);
        didSplit = true;
        break; // restart loop since DOM changed
      }
    }

    if (!didSplit) break;
  }
  // Re-number page headers/footers after auto-splitting
  if (evaluator.pageHeader || evaluator.pageFooter) {
    const allPages = wrapper.querySelectorAll(".output-page");
    allPages.forEach((pg, idx) => {
      const pageNum = evaluator.startPage + idx;
      // Update or add header (skip first page — chapter title page has no header)
      if (evaluator.pageHeader && idx > 0) {
        let hdr = pg.querySelector(".page-header");
        if (!hdr) {
          hdr = document.createElement("div");
          hdr.className = "page-header";
          hdr.innerHTML = `<div class="header-content"><span class="header-section">${escHtml(evaluator.headerTitle || "")}</span><span class="header-pagenum">${pageNum}</span></div><hr class="header-rule">`;
          pg.insertBefore(hdr, pg.firstChild);
        } else {
          const numEl = hdr.querySelector(".header-pagenum");
          if (numEl) numEl.textContent = String(pageNum);
        }
      } else if (evaluator.pageHeader && idx === 0) {
        // Remove header from first page if it exists
        const hdr = pg.querySelector(".page-header");
        if (hdr) hdr.remove();
      }
      // Update or add footer
      if (evaluator.pageFooter) {
        let ftr = pg.querySelector(".page-footer");
        if (!ftr) {
          ftr = document.createElement("div");
          ftr.className = "page-footer";
          ftr.innerHTML = `<hr class="footer-rule"><div class="footer-content"><span class="footer-section"></span><span class="footer-pagenum">${pageNum}</span></div>`;
          pg.appendChild(ftr);
        } else {
          const numEl = ftr.querySelector(".footer-pagenum");
          if (numEl) numEl.textContent = String(pageNum);
        }
      }
    });
  }
}

// ─── Output Rulers (Word-style, JS-created canvas overlays) ────────
const outputPanel = document.getElementById("outputPanel") as HTMLElement;

// Create ruler canvases
const outRulerH = document.createElement("canvas");
outRulerH.className = "output-ruler-h-overlay";
const outRulerV = document.createElement("canvas");
outRulerV.className = "output-ruler-v-overlay";
const outRulerCorner = document.createElement("div");
outRulerCorner.className = "output-ruler-corner-overlay";

// Insert into output-panel (which has position:relative)
outputPanel.appendChild(outRulerCorner);
outputPanel.appendChild(outRulerH);
outputPanel.appendChild(outRulerV);

// Position overlays below the "Output" header
function positionOutputRulers() {
  const header = outputPanel.querySelector(".output-header") as HTMLElement;
  const headerH = header ? header.offsetHeight : 30;
  const panelW = outputPanel.offsetWidth;
  outRulerCorner.style.top = `${headerH}px`;
  outRulerH.style.top = `${headerH}px`;
  outRulerH.style.width = `${panelW - 18 - 16}px`;  // -18 vRuler, -16 scrollbar
  outRulerV.style.top = `${headerH + 18}px`;
  outRulerV.style.height = `${outputPanel.offsetHeight - headerH - 18}px`;
}

/** Get the first output page's bounding rect relative to the output panel */
function getPageGeometry() {
  const page = output.querySelector(".output-page") as HTMLElement;
  if (!page) return null;
  const pageRect = page.getBoundingClientRect();
  const panelRect = outputPanel.getBoundingClientRect();
  const headerEl = outputPanel.querySelector(".output-header") as HTMLElement;
  const headerH = headerEl ? headerEl.offsetHeight : 30;
  // Page position relative to the ruler overlay origin
  const rulerHLeft = 18; // ruler H starts at left=18px (after vRuler)
  return {
    // Page left edge relative to hRuler canvas origin
    pageX: pageRect.left - panelRect.left - rulerHLeft,
    // Page visual width and height (after CSS zoom)
    pageW: pageRect.width,
    pageH: pageRect.height,
    // Page top relative to vRuler canvas origin (vRuler starts at headerH + 18)
    pageY: pageRect.top - panelRect.top - headerH - 18,
    headerH,
  };
}

/** Draw horizontal ruler on the Output panel */
function drawOutputHRuler() {
  const geo = getPageGeometry();
  const dpr = window.devicePixelRatio || 1;
  const cssW = outRulerH.offsetWidth;
  const cssH = 18;
  outRulerH.width = Math.round(cssW * dpr);
  outRulerH.height = Math.round(cssH * dpr);
  const ctx = outRulerH.getContext("2d")!;
  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);

  // Background
  ctx.fillStyle = "#d0ccc8";
  ctx.fillRect(0, 0, cssW, cssH);

  if (!geo) return;

  // Derive scale: visual page width / A4 CSS width (794px)
  const a4Wmm = 210, marginLmm = 20, marginRmm = 15;
  const pxPerMm = 96 / 25.4;
  const a4Wpx = a4Wmm * pxPerMm;
  const visScale = geo.pageW / a4Wpx;
  const marginL = marginLmm * pxPerMm * visScale;
  const marginR = marginRmm * pxPerMm * visScale;

  // Content area highlight
  const cLeft = Math.max(0, geo.pageX + marginL);
  const cRight = Math.min(cssW, geo.pageX + geo.pageW - marginR);
  if (cRight > cLeft) {
    ctx.fillStyle = "#f0eeec";
    ctx.fillRect(cLeft, 0, cRight - cLeft, cssH);
  }

  // Cm ticks
  const cmPx = (96 / 2.54) * visScale;
  const totalCm = Math.ceil(a4Wmm / 10);
  const labelInterval = cmPx < 8 ? 10 : cmPx < 14 ? 5 : cmPx < 22 ? 2 : 1;
  const rulerFontSize = Math.max(6, Math.min(10, Math.round(cmPx * 0.6)));
  ctx.font = `${rulerFontSize}px 'Segoe UI', Arial, sans-serif`;
  ctx.textAlign = "center";
  ctx.textBaseline = "bottom";

  for (let cm = 0; cm <= totalCm; cm++) {
    const x = geo.pageX + cm * cmPx;
    if (x < -1 || x > cssW + 1) continue;
    const isLabel = cm % labelInterval === 0;
    ctx.strokeStyle = "#777";
    ctx.lineWidth = 0.8;
    ctx.beginPath();
    ctx.moveTo(x, cssH - 1);
    ctx.lineTo(x, cssH - (isLabel ? 7 : 4));
    ctx.stroke();
    if (cm > 0 && isLabel) {
      ctx.fillStyle = "#555";
      ctx.fillText(`${cm}`, x, cssH - 7);
    }
    if (cmPx >= 10) {
      const halfX = x + cmPx / 2;
      if (halfX >= 0 && halfX <= cssW) {
        ctx.beginPath();
        ctx.moveTo(halfX, cssH - 1);
        ctx.lineTo(halfX, cssH - 3);
        ctx.stroke();
      }
    }
  }

  // Margin triangles
  ctx.fillStyle = "#666";
  const triL = geo.pageX + marginL;
  const triR = geo.pageX + geo.pageW - marginR;
  if (triL >= 0 && triL <= cssW) {
    ctx.beginPath();
    ctx.moveTo(triL, cssH - 1);
    ctx.lineTo(triL - 4, cssH - 5);
    ctx.lineTo(triL + 4, cssH - 5);
    ctx.closePath(); ctx.fill();
  }
  if (triR >= 0 && triR <= cssW) {
    ctx.beginPath();
    ctx.moveTo(triR, cssH - 1);
    ctx.lineTo(triR - 4, cssH - 5);
    ctx.lineTo(triR + 4, cssH - 5);
    ctx.closePath(); ctx.fill();
  }

  // Bottom border
  ctx.strokeStyle = "#aaa";
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.moveTo(0, cssH - 0.5);
  ctx.lineTo(cssW, cssH - 0.5);
  ctx.stroke();
}

/** Draw vertical ruler on the Output panel */
function drawOutputVRuler() {
  const dpr = window.devicePixelRatio || 1;
  const cssW = 18;
  const cssH = outRulerV.offsetHeight;
  if (cssH <= 0) return;
  outRulerV.width = Math.round(cssW * dpr);
  outRulerV.height = Math.round(cssH * dpr);
  const ctx = outRulerV.getContext("2d")!;
  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);

  // Background
  ctx.fillStyle = "#d0ccc8";
  ctx.fillRect(0, 0, cssW, cssH);

  // Get all visible pages
  const pages = output.querySelectorAll(".output-page");
  if (!pages.length) return;

  const panelRect = outputPanel.getBoundingClientRect();
  const headerEl = outputPanel.querySelector(".output-header") as HTMLElement;
  const headerH = headerEl ? headerEl.offsetHeight : 30;
  const vRulerTop = panelRect.top + headerH + 18;

  const a4Hmm = 297, marginTmm = 15, marginBmm = 15;
  const pxPerMm = 96 / 25.4;

  // Process each visible page
  for (const pg of pages) {
    const pgRect = (pg as HTMLElement).getBoundingClientRect();
    const pageTopInRuler = pgRect.top - vRulerTop;
    const pageH = pgRect.height;

    // Skip pages completely outside view
    if (pageTopInRuler + pageH < -10 || pageTopInRuler > cssH + 10) continue;

    const visScale = pageH / (a4Hmm * pxPerMm);
    const marginT = marginTmm * pxPerMm * visScale;
    const marginB = marginBmm * pxPerMm * visScale;

    // Content area highlight
    const contentTop = pageTopInRuler + marginT;
    const contentBottom = pageTopInRuler + pageH - marginB;
    const clampedTop = Math.max(0, contentTop);
    const clampedBottom = Math.min(cssH, contentBottom);
    if (clampedBottom > clampedTop) {
      ctx.fillStyle = "#f0eeec";
      ctx.fillRect(0, clampedTop, cssW, clampedBottom - clampedTop);
    }

    // Cm ticks
    const cmPx = (96 / 2.54) * visScale;
    const totalCm = Math.ceil(a4Hmm / 10);
    const labelInterval = cmPx < 8 ? 10 : cmPx < 14 ? 5 : cmPx < 22 ? 2 : 1;
    const vFontSize = Math.max(6, Math.min(10, Math.round(cmPx * 0.6)));
    ctx.font = `${vFontSize}px 'Segoe UI', Arial, sans-serif`;
    ctx.textAlign = "center";
    ctx.textBaseline = "middle";

    for (let cm = 0; cm <= totalCm; cm++) {
      const y = pageTopInRuler + cm * cmPx;
      if (y < -1 || y > cssH + 1) continue;
      const isLabel = cm % labelInterval === 0;
      ctx.strokeStyle = "#777";
      ctx.lineWidth = 0.8;
      ctx.beginPath();
      ctx.moveTo(cssW - 1, y);
      ctx.lineTo(cssW - (isLabel ? 7 : 4), y);
      ctx.stroke();
      if (cm > 0 && isLabel && y > 4) {
        ctx.fillStyle = "#555";
        ctx.fillText(`${cm}`, cssW / 2 - 1, y);
      }
      if (cmPx >= 10) {
        const halfY = y + cmPx / 2;
        if (halfY >= 0 && halfY <= cssH) {
          ctx.beginPath();
          ctx.moveTo(cssW - 1, halfY);
          ctx.lineTo(cssW - 3, halfY);
          ctx.stroke();
        }
      }
    }

    // Margin triangles
    ctx.fillStyle = "#666";
    if (contentTop >= 0 && contentTop <= cssH) {
      ctx.beginPath();
      ctx.moveTo(cssW - 1, contentTop);
      ctx.lineTo(cssW - 5, contentTop - 2);
      ctx.lineTo(cssW - 5, contentTop + 2);
      ctx.closePath(); ctx.fill();
    }
    if (contentBottom >= 0 && contentBottom <= cssH) {
      ctx.beginPath();
      ctx.moveTo(cssW - 1, contentBottom);
      ctx.lineTo(cssW - 5, contentBottom - 2);
      ctx.lineTo(cssW - 5, contentBottom + 2);
      ctx.closePath(); ctx.fill();
    }
  }

  // Right border
  ctx.strokeStyle = "#aaa";
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.moveTo(cssW - 0.5, 0);
  ctx.lineTo(cssW - 0.5, cssH);
  ctx.stroke();
}

function updateOutputRulers() {
  positionOutputRulers();
  drawOutputHRuler();
  drawOutputVRuler();
}

// ─── Shared CSS-transform zoom ──────────────────────────────────────
// zoomLevel is applied as CSS transform on the canvas and CSS zoom on
// the output wrapper. This makes EVERYTHING scale visually: pages,
// text, equations, @{draw} diagrams, matrices, etc.

function syncZoom() {
  const zoom = editor.getDebugInfo().zoomLevel;

  // Canvas panel: CSS zoom (changes layout size → scrollbars work naturally)
  (mathCanvasEl.style as any).zoom = `${zoom}`;

  // Output panel: compute SAME auto-fit scale as MathCanvas (same formula)
  // so both pages are always identical size regardless of timing
  const wrapper = output.querySelector(".output-pages-wrapper") as HTMLElement;
  if (wrapper) {
    const a4Wpx = 210 * 96 / 25.4;            // 794px = A4 width
    const vRulerW = 18, sbW = 10, sbMargin = 2; // same as MathEditor constants
    // Use canvas width if visible, else use codeInput/editorPanel width
    let panelW = mathCanvasEl.clientWidth;
    if (!panelW) panelW = codeInput.clientWidth || output.clientWidth;
    const availW = panelW - sbW - sbMargin - vRulerW;
    const scale = Math.min((availW - 20) / a4Wpx, 1);
    const effectiveZoom = scale * zoom;
    wrapper.style.zoom = `${effectiveZoom}`;

    // Font sizes are controlled by Txt/Eq toolbar inputs (no automatic compensation)

    // Dynamic padding-top: match MathCanvas gap exactly
    // MathCanvas pagesStartY = rulerH(18) + max(4, 12*scale), no zoom mult
    const rulerH = 18;
    const mcPageGap = Math.max(4, 12 * scale);
    const dynPadTop = Math.round(rulerH + mcPageGap);
    output.style.paddingTop = `${dynPadTop}px`;
  }

  updateOutputRulers();
}

// Auto-fit al cargar y al cambiar tamaño — re-render canvas then sync
window.addEventListener("resize", () => {
  editor.resize();          // recomputes autoFitScale
  syncZoom();               // includes updateOutputRulers()
});
setTimeout(() => { editor.resize(); syncZoom(); }, 100);
setTimeout(() => { updateOutputRulers(); }, 200);

// When canvas zoom changes → sync output
editor.onZoomChange = (_zoom) => {
  syncZoom();
};

// Global Ctrl+wheel → always route to our shared zoom (prevent browser zoom)
document.addEventListener("wheel", (e) => {
  if (!e.ctrlKey) return;
  e.preventDefault();
  const delta = e.deltaY > 0 ? -0.05 : 0.05;
  const info = editor.getDebugInfo();
  const newZoom = Math.max(0.5, Math.min(3.0, info.zoomLevel + delta));
  editor.setZoom(newZoom);    // fires onZoomChange → syncZoom
}, { passive: false });

// ─── Scroll sync: MathCanvas ↔ Output ───────────────────
let scrollSyncing = false;

// Canvas scroll → Output scroll
editor.onScrollChange = (fraction) => {
  if (scrollSyncing) return;
  scrollSyncing = true;
  const maxScroll = output.scrollHeight - output.clientHeight;
  if (maxScroll > 0) output.scrollTop = fraction * maxScroll;
  scrollSyncing = false;
};

// Output scroll → Canvas scroll + update vertical ruler
output.addEventListener("scroll", () => {
  if (scrollSyncing) return;
  scrollSyncing = true;
  const maxScroll = output.scrollHeight - output.clientHeight;
  const fraction = maxScroll > 0 ? output.scrollTop / maxScroll : 0;
  editor.setScrollFraction(fraction);
  scrollSyncing = false;
  updateOutputRulers();
});

// ─── Output → Code navigation (click ← arrow) ──────────

/** Measure the pixel Y-position of a character offset using the syntaxLayer
 *  DOM (Range API). This is pixel-perfect because the syntaxLayer mirrors the
 *  textarea layout exactly. Falls back to a hidden mirror div for small files
 *  or when syntaxLayer is unavailable. */
function measureCursorY(charOffset: number): number {
  // Try syntaxLayer Range API (fast, accurate for any file size)
  if (syntaxLayer) {
    const walker = document.createTreeWalker(syntaxLayer, NodeFilter.SHOW_TEXT);
    let pos = 0;
    while (walker.nextNode()) {
      const len = walker.currentNode.textContent!.length;
      if (pos + len > charOffset) {
        const range = document.createRange();
        const off = charOffset - pos;
        range.setStart(walker.currentNode, off);
        range.setEnd(walker.currentNode, Math.min(off + 1, len));
        const rect = range.getBoundingClientRect();
        const slRect = syntaxLayer.getBoundingClientRect();
        // Subtract syntaxLayer padding so result is content-relative
        // (consistent with mirror fallback which has padding:0)
        const slPad = parseFloat(getComputedStyle(syntaxLayer).paddingTop) || 0;
        return rect.top - slRect.top + syntaxLayer.scrollTop - slPad;
      }
      pos += len;
    }
  }
  // Fallback: hidden mirror div (for small files without syntaxLayer)
  const cs = getComputedStyle(codeInput);
  const mirror = document.createElement("div");
  mirror.style.cssText = `
    position:absolute; visibility:hidden; white-space:pre-wrap; word-wrap:break-word;
    font:${cs.font}; line-height:${cs.lineHeight}; tab-size:${cs.tabSize};
    width:${codeInput.clientWidth - parseFloat(cs.paddingLeft) - parseFloat(cs.paddingRight)}px;
    padding:0; border:0; margin:0;
  `;
  const before = codeInput.value.substring(0, charOffset);
  const afterChar = codeInput.value.substring(charOffset, charOffset + 1) || " ";
  mirror.innerHTML = escHtml(before) + '<span id="__cursorProbe">' + escHtml(afterChar) + '</span>';
  document.body.appendChild(mirror);
  const probe = mirror.querySelector("#__cursorProbe") as HTMLElement;
  const cursorY = probe ? probe.offsetTop : mirror.scrollHeight;
  document.body.removeChild(mirror);
  return cursorY;
}

/** Scroll the code textarea to a given source-line index and flash-highlight it */
function scrollCodeToLine(srcLineIdx: number) {
  const lines = codeInput.value.split("\n");
  let charOffset = 0;
  for (let i = 0; i < srcLineIdx && i < lines.length; i++) {
    charOffset += lines[i].length + 1;
  }

  // Place cursor at the start of the line
  codeInput.focus();
  codeInput.selectionStart = charOffset;
  codeInput.selectionEnd = charOffset;

  const lineHeight = parseFloat(getComputedStyle(codeInput).lineHeight) || 15;
  const padTop = parseFloat(getComputedStyle(codeInput).paddingTop) || 0;

  setTimeout(() => {
    // Get exact Y from syntaxLayer DOM (pixel-perfect via Range API)
    const cursorY = measureCursorY(charOffset);

    // Scroll to center the cursor vertically
    const visibleH = codeInput.clientHeight;
    codeInput.scrollTop = Math.max(0, cursorY - visibleH / 2 + padTop);
    codeInput.scrollLeft = 0;

    if (syntaxLayer) {
      syntaxLayer.scrollTop = codeInput.scrollTop;
      syntaxLayer.scrollLeft = codeInput.scrollLeft;

      // Flash at cursorY + padTop (consistent with scroll: always centered)
      const flash = document.createElement("div");
      flash.className = "line-highlight-flash";
      flash.style.top = `${cursorY + padTop}px`;
      flash.style.height = `${lineHeight}px`;
      syntaxLayer.appendChild(flash);
      flash.addEventListener("animationend", () => flash.remove());
    }
  }, 0);
}

// Delegated click handler on output panel for [data-line] elements
output.addEventListener("click", (e) => {
  const target = (e.target as HTMLElement).closest("[data-line]") as HTMLElement | null;
  if (!target) return;
  const lineIdx = parseInt(target.dataset.line || "", 10);
  if (isNaN(lineIdx) || lineIdx < 0) return;
  scrollCodeToLine(lineIdx);
});

// ─── Go-To dialog (Ctrl+G) ──────────────────────────────
const gotoBar = document.createElement("div");
gotoBar.className = "goto-bar";
gotoBar.innerHTML = `
  <label>Ir a:</label>
  <input type="text" class="goto-input" placeholder="página, ecuación (5.14), texto..." />
  <span class="goto-status"></span>
  <span class="goto-hint">Enter\u2193 Shift+Enter\u2191</span>
  <button class="goto-close">\u00d7</button>
`;
outputPanel.style.position = "relative";
outputPanel.insertBefore(gotoBar, outputPanel.children[1]); // after .output-header

const gotoInput = gotoBar.querySelector(".goto-input") as HTMLInputElement;
const gotoClose = gotoBar.querySelector(".goto-close") as HTMLButtonElement;
const gotoStatus = gotoBar.querySelector(".goto-status") as HTMLSpanElement;
let gotoHighlight: HTMLElement | null = null;
let gotoMatches: HTMLElement[] = [];
let gotoMatchIdx = -1;
let gotoLastQuery = "";

function openGotoBar() {
  gotoBar.classList.add("visible");
  gotoInput.value = "";
  gotoStatus.textContent = "";
  gotoInput.focus();
  clearGotoHighlight();
  gotoMatches = [];
  gotoMatchIdx = -1;
  gotoLastQuery = "";
}
function closeGotoBar() {
  gotoBar.classList.remove("visible");
  clearGotoHighlight();
  gotoMatches = [];
  gotoMatchIdx = -1;
  gotoLastQuery = "";
  gotoStatus.textContent = "";
  codeInput.focus();
}
function clearGotoHighlight() {
  if (gotoHighlight) { gotoHighlight.remove(); gotoHighlight = null; }
}

/** Scroll a target element into view within the output panel */
function scrollOutputTo(el: HTMLElement) {
  clearGotoHighlight();
  let top = 0;
  let node: HTMLElement | null = el;
  while (node && node !== output) {
    top += node.offsetTop;
    node = node.offsetParent as HTMLElement | null;
  }
  output.scrollTop = Math.max(0, top - 60);

  const flashEl = document.createElement("div");
  flashEl.style.cssText = `
    position: absolute; left: 0; right: 0;
    background: rgba(212, 175, 55, 0.25);
    pointer-events: none; border-left: 3px solid #D4AF37;
    transition: opacity 0.5s ease-out;
    z-index: 50;
  `;
  flashEl.style.top = `${top}px`;
  flashEl.style.height = `${Math.max(el.offsetHeight, 20)}px`;
  const wrapper = output.querySelector(".output-pages-wrapper") as HTMLElement;
  if (wrapper) {
    wrapper.style.position = "relative";
    wrapper.appendChild(flashEl);
  }
  gotoHighlight = flashEl;
  setTimeout(() => { flashEl.style.opacity = "0"; }, 1500);
  setTimeout(() => { flashEl.remove(); if (gotoHighlight === flashEl) gotoHighlight = null; }, 2100);
}

/** Collect equation matches */
function collectEqMatches(eqNum: string, results: HTMLElement[]) {
  const pattern = `(${eqNum})`;
  const seen = new Set<HTMLElement>();
  const walker = document.createTreeWalker(output, NodeFilter.SHOW_TEXT, null);
  let textNode: Node | null;
  while ((textNode = walker.nextNode())) {
    const txt = textNode.textContent || "";
    if (txt.includes(pattern)) {
      const parent = textNode.parentElement;
      if (parent) {
        const container = (parent.closest("[data-line]") as HTMLElement) || parent;
        if (!seen.has(container)) { results.push(container); seen.add(container); }
      }
    }
  }
}

/** Collect all matching elements for a query */
function collectMatches(query: string): HTMLElement[] {
  const q = query.trim();
  if (!q) return [];
  const results: HTMLElement[] = [];

  // 1. Pure integer → page number
  if (/^\d+$/.test(q)) {
    const pageNum = parseInt(q, 10);
    const startNum = evaluator.startPage;
    const pages = output.querySelectorAll(".output-page");
    const idx = pageNum - startNum;
    if (idx >= 0 && idx < pages.length) { results.push(pages[idx] as HTMLElement); return results; }
  }

  // 2. "p123" or "pag 123" → page
  const pageMatch = q.match(/^(?:p|pag|page|p\u00e1gina)\s*(\d+)$/i);
  if (pageMatch) {
    const pageNum = parseInt(pageMatch[1], 10);
    const startNum = evaluator.startPage;
    const pages = output.querySelectorAll(".output-page");
    const idx = pageNum - startNum;
    if (idx >= 0 && idx < pages.length) { results.push(pages[idx] as HTMLElement); return results; }
  }

  // 3. Number with dot → equation (e.g., "5.14")
  if (/^\d+\.\d+$/.test(q)) { collectEqMatches(q, results); if (results.length) return results; }

  // 4. "eq 5.14" or "ec 5.14" → equation
  const eqMatch = q.match(/^(?:eq|ec|ecu)\s*(.+)$/i);
  if (eqMatch) { collectEqMatches(eqMatch[1].trim(), results); if (results.length) return results; }

  // 5. "(5.14)" with parens → equation
  const parenMatch = q.match(/^\((.+)\)$/);
  if (parenMatch) { collectEqMatches(parenMatch[1].trim(), results); if (results.length) return results; }

  // 6. Text search
  const lower = q.toLowerCase();
  const seen = new Set<HTMLElement>();
  const headings = output.querySelectorAll("h1, h2, h3");
  for (const h of headings) {
    if ((h.textContent || "").toLowerCase().includes(lower)) {
      const el = h as HTMLElement;
      if (!seen.has(el)) { results.push(el); seen.add(el); }
    }
  }
  const allDL = output.querySelectorAll("[data-line]");
  for (const el of allDL) {
    const htmlEl = el as HTMLElement;
    if (seen.has(htmlEl)) continue;
    if ((el.textContent || "").toLowerCase().includes(lower)) { results.push(htmlEl); seen.add(htmlEl); }
  }
  return results;
}

/** Navigate to match at given index */
function gotoMatchAt(idx: number) {
  if (!gotoMatches.length) return;
  gotoMatchIdx = ((idx % gotoMatches.length) + gotoMatches.length) % gotoMatches.length;
  scrollOutputTo(gotoMatches[gotoMatchIdx]);
  gotoStatus.textContent = `${gotoMatchIdx + 1} / ${gotoMatches.length}`;
}

/** Process Go-To query */
function processGotoQuery(query: string, direction: number = 1) {
  const q = query.trim();
  if (!q) { gotoStatus.textContent = ""; return; }
  if (q === gotoLastQuery && gotoMatches.length > 0) {
    gotoMatchAt(gotoMatchIdx + direction);
    return;
  }
  gotoLastQuery = q;
  gotoMatches = collectMatches(q);
  gotoMatchIdx = -1;
  if (gotoMatches.length === 0) {
    gotoStatus.textContent = "0 resultados";
    gotoStatus.style.color = "#c44";
    return;
  }
  gotoStatus.style.color = "#666";
  gotoMatchAt(direction > 0 ? 0 : gotoMatches.length - 1);
}

gotoInput.addEventListener("keydown", (e) => {
  if (e.key === "Enter") { e.preventDefault(); processGotoQuery(gotoInput.value, e.shiftKey ? -1 : 1); }
  if (e.key === "Escape") { e.preventDefault(); closeGotoBar(); }
});
gotoInput.addEventListener("input", () => {
  const q = gotoInput.value.trim();
  if (q !== gotoLastQuery) { gotoLastQuery = ""; gotoMatchIdx = -1; gotoMatches = []; gotoStatus.textContent = ""; gotoStatus.style.color = "#666"; }
});
gotoClose.addEventListener("click", closeGotoBar);

// Global Ctrl+G handler
document.addEventListener("keydown", (e) => {
  if ((e.ctrlKey || e.metaKey) && e.key.toLowerCase() === "g") {
    e.preventDefault();
    if (gotoBar.classList.contains("visible")) closeGotoBar();
    else openGotoBar();
  }
});

// ─── Keyboard (Calculate mode textarea) ─────────────────
codeInput.addEventListener("keydown", (e) => {
  if (e.key === "F5") { e.preventDefault(); runCode(); return; }
  if (e.key === "Enter" && (e.ctrlKey || e.metaKey)) { e.preventDefault(); runCode(); return; }
  if (e.key === "Tab") {
    e.preventDefault();
    const s = codeInput.selectionStart;
    const end = codeInput.selectionEnd;
    codeInput.value = codeInput.value.substring(0, s) + "  " + codeInput.value.substring(end);
    codeInput.selectionStart = codeInput.selectionEnd = s + 2;
  }
});

// AutoRun on input (Calculate mode)
let autoRunTimer: number | null = null;
codeInput.addEventListener("input", () => {
  if (!chkAutoRun.checked) return;
  if (autoRunTimer) clearTimeout(autoRunTimer);
  autoRunTimer = window.setTimeout(runCode, 400);
});

// ─── HTML escaping ──────────────────────────────────────
function escHtml(s: string): string {
  return s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
}

// ═══════════════════════════════════════════════════════════
// RENDERER - Genera HTML con clases de template.html
// ═══════════════════════════════════════════════════════════

// Global figure counter (reset each render)
let _figCount = 0;
// Store figure data for zoom overlay re-render
const _figData: Map<number, { w: number; h: number; commands: string[]; name?: string }> = new Map();

/** Render buffered @{eq} lines with "=" alignment for multi-line groups */
function renderEqBlockAligned(buffer: { display: string; dl: string }[], align: string, fontSize?: string): string {
  // Parse all lines: extract eq number, detect "=" for alignment
  interface EqP { empty?: boolean; left?: string; right?: string; full?: string; hasEquals?: boolean; eqNum?: string; dl: string; }
  const parsed: EqP[] = [];
  for (const item of buffer) {
    const trimmed = item.display;
    if (!trimmed) { parsed.push({ empty: true, dl: item.dl }); continue; }
    const numMatch = trimmed.match(/\((\d+(?:\.\d+)?[a-z]?)\)\s*$/);
    let eqText = trimmed;
    let eqNum = "";
    if (numMatch) { eqText = trimmed.slice(0, numMatch.index).trim(); eqNum = numMatch[1]; }
    const eqIdx = eqText.indexOf(" = ");
    if (eqIdx >= 0) {
      parsed.push({ left: eqText.slice(0, eqIdx).trim(), right: eqText.slice(eqIdx + 3).trim(), hasEquals: true, eqNum, dl: item.dl });
    } else {
      parsed.push({ full: eqText, hasEquals: false, eqNum, dl: item.dl });
    }
  }
  // Use aligned table when >1 non-empty lines and ≥50% have "="
  const nonEmpty = parsed.filter(p => !p.empty);
  const withEquals = nonEmpty.filter(p => p.hasEquals);
  const useAligned = nonEmpty.length > 1 && withEquals.length >= nonEmpty.length * 0.5;

  const fsStyle = fontSize ? `font-size:${fontSize}px;` : "";

  if (useAligned) {
    let h = `<div class="eq-block" style="margin:8px 0;${fsStyle}">`;
    h += `<table class="eq-align-tbl" style="width:100%;border-collapse:collapse;">`;
    h += `<colgroup><col style="width:50%"><col><col><col><col style="width:50%"></colgroup>`;
    for (const p of parsed) {
      if (p.empty) { h += `<tr><td colspan="5" style="height:4px"></td></tr>`; continue; }
      h += `<tr>`;
      h += `<td></td>`; // left spacer — centers equation columns
      if (p.hasEquals) {
        h += `<td class="eq"${p.dl} style="text-align:right;padding:2px 0;white-space:nowrap;line-height:2.2;">${renderEquationText(p.left!)}</td>`;
        h += `<td class="eq" style="text-align:center;padding:2px 4px;white-space:nowrap;line-height:2.2;"> = </td>`;
        h += `<td class="eq"${p.dl} style="text-align:left;padding:2px 0;white-space:nowrap;line-height:2.2;">${renderEquationText(p.right!)}</td>`;
      } else {
        h += `<td class="eq"${p.dl} colspan="3" style="text-align:left;padding:2px 0;white-space:nowrap;line-height:2.2;">${renderEquationText(p.full!)}</td>`;
      }
      h += p.eqNum
        ? `<td style="text-align:right;white-space:nowrap;font-style:normal;line-height:2.2;">(${p.eqNum})</td>`
        : `<td></td>`;
      h += `</tr>`;
    }
    h += `</table></div>`;
    return h;
  }

  // Single line or no alignment: original centered behavior
  let h = `<div class="eq-block" style="text-align:${align};margin:8px 0;${fsStyle}">`;
  for (const item of buffer) {
    const trimmed = item.display;
    if (!trimmed) { h += '<div style="height:4px"></div>'; continue; }
    const numMatch = trimmed.match(/\((\d+(?:\.\d+)?[a-z]?)\)\s*$/);
    let eqText = trimmed;
    let eqNum = "";
    if (numMatch) { eqText = trimmed.slice(0, numMatch.index).trim(); eqNum = numMatch[1]; }
    h += `<p class="eq"${item.dl} style="margin:4px 0;line-height:2.2;">`;
    h += renderEquationText(eqText);
    if (eqNum) h += `<span style="float:right;font-style:normal;margin-left:24px">(${eqNum})</span>`;
    h += "</p>";
  }
  return h + "</div>";
}

function renderResults(results: LineResult[], sourceCode: string): string {
  const html: string[] = [];
  let inColumns = false;
  let columnCount = 0;
  let columnItems: {html: string, lineIndex: number}[] = [];
  let inEqBlock = false;
  let eqBlockAlign = "center";
  let eqBlockSize = "";  // font size from @{eq size:N}
  let eqBlockBuffer: { display: string; dl: string }[] = []; // buffer eqlines for alignment
  let currentAlign = "left"; // tracks @{config align:X} directive
  const sourceLines = sourceCode.split("\n");
  _figCount = 0;
  _figData.clear();

  for (const r of results) {
    let srcLine = sourceLines[r.lineIndex]?.trim() ?? "";
    // Strip inline // comments from source line for rendering
    const cmtIdx = srcLine.indexOf("//");
    if (cmtIdx >= 0) srcLine = srcLine.slice(0, cmtIdx).trim();
    // data-line attribute for output→code navigation
    const dl = ` data-line="${r.lineIndex}"`;

    // Detect @{columns N} start
    const colMatch = srcLine.match(/^@\{columns\s+(\d+)\}/i);
    if (colMatch) {
      inColumns = true;
      columnCount = parseInt(colMatch[1]);
      columnItems = [];
      continue;
    }

    // Empty line or heading/comment exits columns mode
    if (inColumns && (r.type === "empty" || r.type === "heading" || r.type === "comment")) {
      if (columnItems.length > 0) {
        html.push(renderColumnsGrid(columnItems, columnCount));
        columnItems = [];
      }
      inColumns = false;
    }

    if (inColumns && (r.type === "assignment" || r.type === "expression")) {
      columnItems.push({html: renderLineEq(r, srcLine), lineIndex: r.lineIndex});
      continue;
    }

    // Flush remaining columns
    if (inColumns && columnItems.length > 0 && r.type !== "assignment" && r.type !== "expression") {
      html.push(renderColumnsGrid(columnItems, columnCount));
      columnItems = [];
      inColumns = false;
    }

    switch (r.type) {
      case "heading": {
        const match = r.display!.match(/^(#{1,6})\s+(.*)/);
        if (match) {
          const level = match[1].length;
          const headText = match[2];
          const hAlignStyle = currentAlign !== "left" ? ` style="text-align:${currentAlign}"` : "";
          // Book-style chapter heading: "# 5 Grid Frames" → number big, title right-aligned, ruled lines
          if (level === 1) {
            const chapMatch = headText.match(/^(\d+)\s+(.*)/);
            if (chapMatch) {
              html.push(`<h1 class="chapter-heading"${dl}${hAlignStyle}><span class="chapter-num">${escHtml(chapMatch[1])}</span> <span class="chapter-title">${escHtml(chapMatch[2])}</span></h1>`);
            } else {
              html.push(`<h1 class="chapter-heading"${dl}${hAlignStyle}><span class="chapter-title">${escHtml(headText)}</span></h1>`);
            }
          } else if (level === 2) {
            // Section heading: "## 5.2 Efectos" → number spaced from title
            const secMatch = headText.match(/^([\d.]+)\s+(.*)/);
            if (secMatch) {
              html.push(`<h${level} class="section-heading"${dl}${hAlignStyle}><span class="section-num">${escHtml(secMatch[1])}</span><span class="section-title">${escHtml(secMatch[2])}</span></h${level}>`);
            } else {
              html.push(`<h${level}${dl}${hAlignStyle}>${escHtml(headText)}</h${level}>`);
            }
          } else {
            html.push(`<h${level}${dl}${hAlignStyle}>${escHtml(headText)}</h${level}>`);
          }
        }
        break;
      }
      case "comment":
        html.push(`<p class="out-comment"${dl}>${renderCommentMath(r.display!)}</p>`);
        break;
      case "empty":
        html.push(`<div class="out-empty"${dl}></div>`);
        break;
      case "assignment": {
        const aContent = renderLineEq(r, srcLine);
        const aFlex = aContent.includes('class="matrix"') ? "display:flex;align-items:center;flex-wrap:wrap;gap:0 2px;" : "";
        const aAlign = currentAlign !== "left" ? `text-align:${currentAlign};` : "";
        const aStyle = (aFlex || aAlign) ? ` style="${aFlex}${aAlign}"` : "";
        html.push(`<p class="eq out-line"${dl}${aStyle}>${aContent}</p>`);
        break;
      }
      case "expression": {
        const eContent = renderExprResult(r);
        const eFlex = eContent.includes('class="matrix"') ? "display:flex;align-items:center;flex-wrap:wrap;gap:0 2px;" : "";
        const eAlign = currentAlign !== "left" ? `text-align:${currentAlign};` : "";
        const eStyle = (eFlex || eAlign) ? ` style="${eFlex}${eAlign}"` : "";
        html.push(`<p class="eq out-line"${dl}${eStyle}>${eContent}</p>`);
        break;
      }
      case "cells":
        html.push(renderCells(r, dl));
        break;
      case "hrule":
        html.push(`<hr class="out-hrule"${dl} style="border:none;border-top:1.5px solid #333;margin:12px 0;" />`);
        break;
      case "image64": {
        // Embedded base64 image from @{image64 W [H] [name:Name] [align:center|left|right]}
        const imgData = (r as any).imageData || "";
        const imgName = (r as any).imageName || "";
        const imgW = (r as any).drawWidth || 560;
        const imgAlign = (r as any).imageAlign || "center"; // default: center
        if (imgData) {
          html.push(`<div class="out-image64"${dl} style="text-align:${imgAlign};margin:8px 0;">`);
          html.push(`<img src="${imgData}" alt="${escHtml(imgName)}" style="max-width:${imgW}px;width:100%;display:inline-block;" />`);
          html.push(`</div>`);
        }
        break;
      }
      case "eqline": {
        // @{eq} block line — buffer for aligned rendering at block close
        const eqTrimmed = (r.display || "").trim();
        if (inEqBlock) {
          eqBlockBuffer.push({ display: eqTrimmed, dl });
        } else {
          // Standalone eq line (outside block) — render immediately
          if (!eqTrimmed) break;
          const eqNumMatch = eqTrimmed.match(/\((\d+(?:\.\d+)?[a-z]?)\)\s*$/);
          let eqText = eqTrimmed;
          let eqNum = "";
          if (eqNumMatch) { eqText = eqTrimmed.slice(0, eqNumMatch.index).trim(); eqNum = eqNumMatch[1]; }
          let eqHtml = `<p class="eq"${dl} style="margin:4px 0;line-height:2.2;text-align:center;">`;
          eqHtml += renderEquationText(eqText);
          if (eqNum) eqHtml += `<span style="float:right;font-style:normal;margin-left:24px">(${eqNum})</span>`;
          eqHtml += "</p>";
          html.push(eqHtml);
        }
        break;
      }
      case "error":
        html.push(`<div class="out-error"${dl}>${escHtml(r.error!)}</div>`);
        break;
      case "plot": {
        // @{plot} → generate SVG via parser handler
        if (r.plotCommands && r.plotCommands.length > 0) {
          const plotAlignStyle = currentAlign !== "left" ? ` style="text-align:${currentAlign}"` : "";
          const plotHtml = handlePlotBlock(r.plotCommands);
          html.push(`<div class="plot-output"${dl}${plotAlignStyle}>${plotHtml}</div>`);
        }
        break;
      }
      case "svg": {
        // @{svg} → raw SVG passthrough
        if (r.svgLines && r.svgLines.length > 0) {
          const svgAlignStyle = currentAlign !== "left" ? ` style="text-align:${currentAlign}"` : "";
          const svgHtml = handleSvgBlock(r.svgLines);
          html.push(`<div class="svg-output"${dl}${svgAlignStyle}>${svgHtml}</div>`);
        }
        break;
      }
      case "three": {
        // @{three} or @{three W H} → Three.js 3D scene (rendered post-innerHTML)
        if (r.threeLines && r.threeLines.length > 0) {
          const threeUid = `three-output-${r.lineIndex}`;
          const threeW = r.drawWidth || 0;
          const threeH = r.drawHeight || 400;
          const threeAlignStyle = currentAlign !== "left" ? `text-align:${currentAlign};` : "";
          const threeWStyle = threeW ? `width:${threeW}px;max-width:100%;` : "width:100%;";
          html.push(`<div class="three-output"${dl} style="${threeAlignStyle}margin:0.5em 0;">
            <div id="${threeUid}" style="${threeWStyle}height:${threeH}px;border:1px solid #ddd;display:inline-block;"></div>
          </div>`);
        }
        break;
      }
      case "draw": {
        _figCount++;
        const figNum = _figCount;
        const uid = `cad-output-${r.lineIndex}`;
        const w = r.drawWidth || 500;
        const h = r.drawHeight || 400;
        // Caption: if name starts with "Fig" (book reference), bold the "Fig. X.Y" part and show description
        // Otherwise use sequential number + name
        let figCaption: string;
        if (r.drawName) {
          const nameMatch = r.drawName.match(/^(Fig\.?\s*[\d.]+)\s*(.*)/i);
          if (nameMatch) {
            figCaption = nameMatch[2] ? `<b>${escHtml(nameMatch[1])}</b>&ensp;${escHtml(nameMatch[2])}` : `<b>${escHtml(nameMatch[1])}</b>`;
          } else {
            figCaption = `<b>Fig. ${figNum}</b>&ensp;${escHtml(r.drawName)}`;
          }
        } else {
          figCaption = `<b>Fig. ${figNum}</b>`;
        }
        // Store data for zoom re-render
        if (r.drawCommands) _figData.set(figNum, { w, h, commands: [...r.drawCommands], name: r.drawName });
        const figAlign = r.drawAlign || "center";  // figures always centered by default (ignore currentAlign for text)
        const figAlignStyle = figAlign !== "left" ? `text-align:${figAlign};` : "";
        html.push(`<div${dl} style="margin:0.5em 0;${figAlignStyle}">
          <div class="draw-container" id="fig-${figNum}" data-fig="${figNum}" style="display:inline-block;max-width:100%;overflow:hidden;">
            <canvas id="${uid}" width="${w}" height="${h}" style="border:1px solid #ccc;display:block;max-width:100%;height:auto;cursor:pointer;" onclick="window._hkFigZoom(${figNum})"></canvas>
            <div class="draw-caption">
              <span class="draw-fig-label">${figCaption}</span>
              <button class="draw-zoom-btn" title="Ampliar figura (zoom)" onclick="window._hkFigZoom(${figNum})">&#x1F50D;</button>
            </div>
          </div>
        </div>`);
        break;
      }
      case "draw3d": {
        const uid3 = `cad3d-output-${r.lineIndex}`;
        const w3 = r.drawWidth || 500;
        const h3 = r.drawHeight || 400;
        html.push(`<div class="draw3d-container" id="${uid3}"${dl} style="margin:0.5em 0;width:${w3}px;max-width:100%;height:${h3}px;border:1px solid #4488ff;border-radius:4px;overflow:hidden;box-sizing:border-box;"></div>`);
        break;
      }
      case "draw3difc": {
        const uidIfc = `ifc3d-output-${r.lineIndex}`;
        const wIfc = r.drawWidth || 600;
        const hIfc = r.drawHeight || 450;
        html.push(`<div class="draw3d-ifc-container"${dl} style="margin:0.5em 0;">
          <div style="margin-bottom:6px;display:flex;align-items:center;gap:8px;">
            <input type="file" id="${uidIfc}-file" accept=".ifc" style="font-size:12px;">
            <span id="${uidIfc}-status" style="font-size:11px;color:#888;">Selecciona un archivo .ifc</span>
          </div>
          <div id="${uidIfc}" style="width:${wIfc}px;max-width:100%;height:${hIfc}px;border:1px solid #4488ff;border-radius:4px;overflow:hidden;background:#1a1a2e;box-sizing:border-box;"></div>
          <div id="${uidIfc}-views" style="display:flex;flex-wrap:wrap;gap:8px;margin-top:8px;"></div>
        </div>`);
        break;
      }
      case "importifc": {
        const uidIfc2 = `ifc-import-${r.lineIndex}`;
        const wI = r.drawWidth || 700;
        const hI = r.drawHeight || 500;
        const btnStyle = `padding:2px 7px;font-size:10px;border:1px solid #555;border-radius:3px;cursor:pointer;background:#2a2a3e;color:#ccc;`;
        html.push(`<div class="draw3d-ifc-container"${dl} style="margin:0.5em 0;">
          <div style="display:flex;align-items:center;gap:4px;margin-bottom:4px;flex-wrap:wrap;">
            <span style="font-size:11px;color:#888;" id="${uidIfc2}-status">Cargando ${r.ifcFile}...</span>
          </div>
          <div id="${uidIfc2}-filters" style="display:none;margin-bottom:4px;">
            <div style="display:flex;gap:3px;flex-wrap:wrap;align-items:center;">
              <span style="font-size:10px;color:#666;margin-right:2px;">Filtros:</span>
              <button data-filter="all" style="${btnStyle}background:#4488ff;color:#fff;">Todo</button>
              <button data-filter="structural" style="${btnStyle}">Estructural</button>
              <button data-filter="connections" style="${btnStyle}">Conexiones</button>
              <button data-filter="columns" style="${btnStyle}">Columnas</button>
              <button data-filter="beams" style="${btnStyle}">Vigas</button>
              <button data-filter="slabs" style="${btnStyle}">Losas</button>
              <button data-filter="rebar" style="${btnStyle}">Refuerzo</button>
              <button data-filter="plates" style="${btnStyle}">Placas</button>
              <button data-filter="members" style="${btnStyle}">Miembros</button>
              <button data-filter="fasteners" style="${btnStyle}">Pernos</button>
              <button data-filter="walls" style="${btnStyle}">Muros</button>
              <button data-filter="openings" style="${btnStyle}">Ventanas</button>
            </div>
          </div>
          <div id="${uidIfc2}" style="width:${wI}px;height:${hI}px;border:1px solid #4488ff;border-radius:4px;overflow:hidden;background:#1a1a2e;cursor:crosshair;"></div>
          <div id="${uidIfc2}-pick" style="font-size:11px;color:#aaa;margin-top:3px;min-height:16px;">Click en un elemento para seleccionar</div>
          <div id="${uidIfc2}-views" style="display:flex;flex-wrap:wrap;gap:8px;margin-top:8px;"></div>
        </div>`);
        break;
      }
      case "directive": {
        // Detect @{pagebreak} → insert page break marker
        if (/^@\{pagebreak/i.test(srcLine)) {
          html.push(`<!--PAGEBREAK-->`);
        }
        // Detect align directive: display = "align:left", "align:center", "align:right"
        const eqDirDisplay = r.display || "";
        const alignDirMatch = eqDirDisplay.match(/^align:(left|center|right)$/i);
        if (alignDirMatch) {
          currentAlign = alignDirMatch[1].toLowerCase();
        }
        // Detect render flags from config display string
        for (const flag of ["frac", "mul", "sup", "sub", "sqrt"] as const) {
          const m = eqDirDisplay.match(new RegExp(`${flag}=(on|off)`, "i"));
          if (m) (renderCfg as any)[flag] = m[1].toLowerCase() === "on";
        }
        // Sync fractions checkbox and renderer with renderCfg.frac
        setFractions(renderCfg.frac);
        chkFractions.checked = renderCfg.frac;
        // Detect eq block open: display = "eq:center:", "eq:left:14", "eq:right:"
        const eqOpenMatch = eqDirDisplay.match(/^eq:(left|center|right):(\d*)$/i);
        if (eqOpenMatch) {
          inEqBlock = true;
          eqBlockAlign = eqOpenMatch[1].toLowerCase();
          eqBlockSize = eqOpenMatch[2] || "";
          eqBlockBuffer = [];
        }
        // Detect eq block close: display = "eq:end" → flush buffered eqlines
        if (eqDirDisplay === "eq:end" && inEqBlock) {
          inEqBlock = false;
          // Render buffered eq lines with "=" alignment and optional font size
          html.push(renderEqBlockAligned(eqBlockBuffer, eqBlockAlign, eqBlockSize));
          eqBlockBuffer = [];
        }
        // Detect function definition: display = "function:name(args)"
        const funcDefMatch = eqDirDisplay.match(/^function:(\w+)\(([^)]*)\)$/);
        if (funcDefMatch) {
          const fName = funcDefMatch[1];
          const fArgs = funcDefMatch[2];
          const argsHTML = fArgs.split(",").map(a => `<var>${escHtml(a.trim())}</var>`).join(", ");
          html.push(`<p class="eq out-line func-def"${dl}><span class="func-keyword">function</span> <var class="func-name">${escHtml(fName)}</var>(${argsHTML})</p>`);
        }
        break;
      }
    }
  }

  if (inColumns && columnItems.length > 0) {
    html.push(renderColumnsGrid(columnItems, columnCount));
  }

  return html.join("\n");
}

/** Post-render: create Three.js scenes for @{three} blocks using local THREE module */
function renderThreeBlocks(results: LineResult[]): void {
  for (const r of results) {
    if (r.type !== "three" || !r.threeLines) continue;
    const uid = `three-output-${r.lineIndex}`;
    const container = document.getElementById(uid);
    if (!container || container.children.length > 0) continue; // already rendered

    try {
      const w = container.clientWidth || 600;
      const h = container.clientHeight || 400;
      const scene = new THREE.Scene();
      scene.background = new THREE.Color(0xf5f5f5);
      const camera = new THREE.PerspectiveCamera(50, w / h, 0.1, 10000);
      camera.position.set(5, 5, 5);
      const renderer = new THREE.WebGLRenderer({ antialias: true, logarithmicDepthBuffer: true, powerPreference: "high-performance" });
      renderer.setPixelRatio(Math.min(window.devicePixelRatio || 1, 2));
      renderer.toneMapping = THREE.ACESFilmicToneMapping;
      renderer.toneMappingExposure = 1.2;
      renderer.setSize(w, h);
      container.appendChild(renderer.domElement);
      const controls = new OrbitControls(camera, renderer.domElement);
      scene.add(new THREE.AmbientLight(0x606060, 0.8));
      const dirLight = new THREE.DirectionalLight(0xffffff, 1.0);
      dirLight.position.set(200, 300, 150);
      scene.add(dirLight);
      const dirLight2 = new THREE.DirectionalLight(0xffffff, 0.4);
      dirLight2.position.set(-100, 200, -100);
      scene.add(dirLight2);

      // Execute DSL-generated JS code with THREE and scene in scope
      const code = processThreeDSL(r.threeLines);
      const execFn = new Function("THREE", "scene", "camera", "controls", "renderer", "container", code);
      execFn(THREE, scene, camera, controls, renderer, container);

      // Resize observer to keep rendering sharp
      const resizeObs = new ResizeObserver(() => {
        const nw = container.clientWidth || w;
        const nh = container.clientHeight || h;
        camera.aspect = nw / nh;
        camera.updateProjectionMatrix();
        renderer.setSize(nw, nh);
      });
      resizeObs.observe(container);

      // Animation loop
      const animate = () => {
        requestAnimationFrame(animate);
        controls.update();
        renderer.render(scene, camera);
      };
      animate();
    } catch (e: any) {
      container.innerHTML = `<div style="color:red;padding:8px;">@{three} error: ${e.message}</div>`;
    }
  }
}

/** Post-render: find draw results and render CAD commands into their canvases */
function renderDrawBlocks(results: LineResult[], pageBg?: string): void {
  for (const r of results) {
    if (r.type !== "draw" || !r.drawCommands) continue;
    const uid = `cad-output-${r.lineIndex}`;
    const canvas = document.getElementById(uid) as HTMLCanvasElement | null;
    if (!canvas) continue;
    const ctx = canvas.getContext("2d");
    if (!ctx) continue;

    const w = r.drawWidth || 500;
    const h = r.drawHeight || 400;
    const eng = new CadEngine();
    eng.canvasW = w;
    eng.canvasH = h;
    // Inherit page background color if no explicit bg command in draw
    if (pageBg) eng.bgColor = pageBg;

    // Execute all CAD CLI commands
    execCommands(eng, r.drawCommands.join("\n"));

    // Auto zoom-fit
    eng.zoomFit();

    // Render to canvas
    eng.renderToCtx(ctx, w, h);
  }
}

/** Post-render: find draw3d results and create Three.js scenes */
function renderDraw3DBlocks(results: LineResult[]): void {
  for (const r of results) {
    if (r.type !== "draw3d" || !r.drawCommands) continue;
    const uid = `cad3d-output-${r.lineIndex}`;
    const container = document.getElementById(uid);
    if (!container) continue;

    const w = r.drawWidth || 500;
    const h = r.drawHeight || 400;

    // Parse 3D commands
    const { shapes, config } = parseDraw3D(r.drawCommands);

    // Create Three.js scene
    const sc = createScene(container, w, h);
    active3DScenes.push(sc);

    // Apply config
    if (config.bg) sc.scene.background = new THREEColor(config.bg);
    if (config.grid === false) {
      const grid = sc.scene.children.find(c => (c as any).isGridHelper);
      if (grid) sc.scene.remove(grid);
    }
    if (config.camX !== undefined) {
      sc.camera.position.set(config.camX!, config.camY!, config.camZ!);
      sc.camera.lookAt(0, 0, 0);
    }

    // Add shapes
    addShapesToScene(sc.scene, shapes);

    // Render orthographic 2D views if requested
    if (config.views && config.views.length > 0) {
      const viewsDiv = document.createElement("div");
      viewsDiv.style.cssText = "display:flex;flex-wrap:wrap;gap:8px;margin-top:8px;";
      const vw = Math.min(w, 350);
      const vh = Math.round(vw * 0.75);
      for (const vname of config.views) {
        const canvas = renderOrthoView(sc.scene, vname as OrthoView, vw, vh);
        canvas.style.cssText = "border:1px solid #ccc;border-radius:3px;";
        viewsDiv.appendChild(canvas);
      }
      container.parentElement!.insertBefore(viewsDiv, container.nextSibling);
    }
  }
}

/** Post-render: wire up IFC file inputs to load models into Three.js */
function renderDraw3DIfcBlocks(results: LineResult[]): void {
  for (const r of results) {
    if (r.type !== "draw3difc") continue;
    const uid = `ifc3d-output-${r.lineIndex}`;
    const fileInput = document.getElementById(`${uid}-file`) as HTMLInputElement | null;
    const container = document.getElementById(uid);
    const statusEl = document.getElementById(`${uid}-status`);
    const viewsDiv = document.getElementById(`${uid}-views`);
    if (!fileInput || !container) continue;

    const w = r.drawWidth || 600;
    const h = r.drawHeight || 450;

    fileInput.addEventListener("change", async () => {
      const file = fileInput.files?.[0];
      if (!file) return;
      if (statusEl) statusEl.textContent = `Cargando ${file.name}...`;
      container.innerHTML = "";
      try {
        const buf = await file.arrayBuffer();
        const sc = createScene(container, w, h);
        sc.scene.background = new THREEColor(0x1a1a2e);
        active3DScenes.push(sc);
        const { meshCount, bbox } = await loadIfcToScene(sc.scene, buf);
        fitCameraToBBox(sc.camera, sc.controls, bbox);
        if (statusEl) statusEl.textContent = `${file.name} — ${meshCount} meshes (cargado)`;
        // Vistas ortograficas
        if (viewsDiv) {
          viewsDiv.innerHTML = "";
          const vw = Math.min(w, 300);
          const vh = Math.round(vw * 0.75);
          for (const vname of ["front", "side", "top"] as OrthoView[]) {
            const canvas = renderOrthoView(sc.scene, vname, vw, vh);
            canvas.style.cssText = "border:1px solid #555;border-radius:3px;";
            viewsDiv.appendChild(canvas);
          }
        }
      } catch (err: any) {
        if (statusEl) statusEl.textContent = `Error: ${err.message}`;
        console.error("IFC load error:", err);
      }
    });
  }
}

/** Post-render: auto-fetch IFC files and load into Three.js scenes */
function renderImportIfcBlocks(results: LineResult[]): void {
  for (const r of results) {
    if (r.type !== "importifc" || !r.ifcFile) continue;
    const uid = `ifc-import-${r.lineIndex}`;
    const container = document.getElementById(uid);
    const statusEl = document.getElementById(`${uid}-status`);
    const viewsDiv = document.getElementById(`${uid}-views`);
    const filtersEl = document.getElementById(`${uid}-filters`);
    if (!container) continue;

    const w = r.drawWidth || 700;
    const h = r.drawHeight || 500;
    const file = r.ifcFile;

    (async () => {
      try {
        const url = file.startsWith("/") || file.startsWith("http") ? file : "/" + file;
        const resp = await fetch(url);
        if (!resp.ok) throw new Error(`HTTP ${resp.status} al cargar ${url}`);
        const buf = await resp.arrayBuffer();
        if (statusEl) statusEl.textContent = `Procesando ${file}...`;
        const sc = createScene(container, w, h);
        sc.scene.background = new THREEColor(0x1a1a2e);
        active3DScenes.push(sc);
        const { meshCount, bbox, detailCategories, elementInfo } = await loadIfcToScene(sc.scene, buf);
        fitCameraToBBox(sc.camera, sc.controls, bbox);

        // Conteo detallado por categoria
        const counts = getDetailCounts(detailCategories);
        const parts: string[] = [];
        if (counts.column)   parts.push(`Col:${counts.column}`);
        if (counts.beam)     parts.push(`Vig:${counts.beam}`);
        if (counts.slab)     parts.push(`Los:${counts.slab}`);
        if (counts.footing)  parts.push(`Zap:${counts.footing}`);
        if (counts.rebar)    parts.push(`Ref:${counts.rebar}`);
        if (counts.plate)    parts.push(`Pla:${counts.plate}`);
        if (counts.member)   parts.push(`Mie:${counts.member}`);
        if (counts.fastener) parts.push(`Per:${counts.fastener}`);
        if (counts.wall)     parts.push(`Mur:${counts.wall}`);
        if (counts.opening)  parts.push(`Ven:${counts.opening}`);
        if (counts.other)    parts.push(`Otr:${counts.other}`);
        if (statusEl) statusEl.textContent =
          `${file} — ${meshCount} meshes (${parts.join(" ")})`;

        // Aplicar filtro inicial desde directiva
        const initFilter = r.ifcFilter || "all";
        if (initFilter !== "all") {
          filterIfcByPreset(detailCategories, initFilter);
        }

        // Activar botones de filtro
        if (filtersEl) {
          filtersEl.style.display = "block";
          const buttons = filtersEl.querySelectorAll("button[data-filter]");
          buttons.forEach((b) => {
            const f = (b as HTMLElement).dataset.filter || "all";
            (b as HTMLElement).style.background = f === initFilter ? "#4488ff" : "#2a2a3e";
            (b as HTMLElement).style.color = f === initFilter ? "#fff" : "#ccc";
          });
          const lineIdx = r.lineIndex;
          buttons.forEach((btn) => {
            btn.addEventListener("click", () => {
              const f = (btn as HTMLElement).dataset.filter || "all";
              filterIfcByPreset(detailCategories, f);
              buttons.forEach((b) => {
                (b as HTMLElement).style.background = b === btn ? "#4488ff" : "#2a2a3e";
                (b as HTMLElement).style.color = b === btn ? "#fff" : "#ccc";
              });
              // Actualizar la linea en el textarea (two-way binding)
              const ta = document.getElementById("codeInput") as HTMLTextAreaElement | null;
              if (ta) {
                const lines = ta.value.split("\n");
                if (lineIdx < lines.length) {
                  const filterSuffix = f === "all" ? "" : " " + f;
                  lines[lineIdx] = `@{import:ifc:${file} ${w} ${h}${filterSuffix}}`;
                  ta.value = lines.join("\n");
                }
              }
            });
          });
        }

        if (viewsDiv) {
          const vw = Math.min(w, 300), vh = Math.round(vw * 0.75);
          for (const vname of ["front", "side", "top"] as OrthoView[]) {
            const canvas = renderOrthoView(sc.scene, vname, vw, vh);
            canvas.style.cssText = "border:1px solid #555;border-radius:3px;";
            viewsDiv.appendChild(canvas);
          }
        }

        // Picking: click para seleccionar elementos
        const pickEl = document.getElementById(`${uid}-pick`);
        const lineIdx = r.lineIndex;
        setupIfcPicking(container, sc.camera, sc.scene, elementInfo, (result) => {
          if (!pickEl) return;
          if (!result) {
            pickEl.textContent = "Click en un elemento para seleccionar";
            pickEl.style.color = "#aaa";
            return;
          }
          const info = result.info;
          const label = info
            ? `[${info.typeName}] ${info.name} (ID:${info.expressID}, cat:${info.category})`
            : `ID:${result.expressID} cat:${result.category}`;
          pickEl.innerHTML = `<span style="color:#ff6600;">▸</span> ${label}`;
          pickEl.style.color = "#ddd";

          // Escribir seleccion como comentario en textarea
          const ta = document.getElementById("codeInput") as HTMLTextAreaElement | null;
          if (ta) {
            const lines = ta.value.split("\n");
            // Buscar si ya hay un comentario de seleccion despues del import
            const selComment = `> Sel: ${label}`;
            const nextLine = lineIdx + 1;
            if (nextLine < lines.length && lines[nextLine].startsWith("> Sel:")) {
              lines[nextLine] = selComment;
            } else {
              lines.splice(nextLine, 0, selComment);
            }
            ta.value = lines.join("\n");
          }
        });
      } catch (err: any) {
        if (statusEl) statusEl.textContent = `Error: ${err.message}`;
        console.error("IFC import error:", err);
      }
    })();
  }
}

/** Renderiza columnas como grid CSS */
function renderColumnsGrid(items: {html: string, lineIndex: number}[], cols: number): string {
  return `<div style="display:grid;grid-template-columns:repeat(${cols},1fr);gap:4px 24px;align-items:baseline;margin:0.3em 0;">
    ${items.map(item => `<p class="eq out-line" data-line="${item.lineIndex}" style="margin:0;display:flex;align-items:center;flex-wrap:wrap;gap:0 2px;">${item.html}</p>`).join("\n")}
  </div>`;
}

// ═══════════════════════════════════════════════════════════
// EQUATION RENDERING - Using .eq var, .eq sub, .eq sup, etc.
// ═══════════════════════════════════════════════════════════

/** Renderiza una linea de asignacion: var = expr = valor */
function renderLineEq(r: LineResult, srcLine: string): string {
  const varName = r.varName ?? "";
  const value = r.value;
  // hideExpr overrides to "r" mode; otherwise use displayMode from @{mode}
  const mode = r.hideExpr ? "r" : r.displayMode;
  // Default unit suffix from @{config units:force,length}
  const duSuffix = r.defaultUnit ? `\u2006<i class="unit">${renderUnitLabel(r.defaultUnit)}</i>` : "";

  // Normalize prime notation in source line: f'_c → f_prime_c
  const srcNorm = srcLine.replace(/([a-zA-Z])'([_a-zA-Z])/g, '$1_prime$2');
  // Extraer la expresion original del source
  const assignMatch = srcNorm.match(/^([a-zA-Z_][\w]*(?:\([^)]*\))?)\s*=\s*(.+)$/);
  let exprText = assignMatch ? assignMatch[2].trim() : "";
  // Strip "& unit" or "| unit" from display — these operators are internal (tounit/to conversion)
  if (exprText.includes("&") && !exprText.includes("&&")) {
    const ai = exprText.indexOf("&");
    exprText = exprText.substring(0, ai).trim();
  }
  if (exprText.includes("|") && !exprText.includes("||")) {
    const pi = exprText.indexOf("|");
    exprText = exprText.substring(0, pi).trim();
  }

  // Nombre de variable con <var> y subindices
  const nameHTML = renderVarName(varName);

  // Si es una funcion definida, solo mostrar la definicion
  if (typeof value === "function" || value === undefined) {
    if (exprText) {
      return `${nameHTML} = ${renderMathExpr(exprText)}`;
    }
    return nameHTML;
  }

  const scope = evaluator.getScope();

  // ── Mode "r": result only ───────────────────────────
  if (mode === "r") {
    if (evaluator.isCellArray(value)) return `${nameHTML} = ${renderCellArrayHTML(value, varName)}`;
    if (evaluator.isMatrix(value)) return `${nameHTML} = ${renderMatrixHTML(value, r.defaultUnit)}`;
    return `${nameHTML} = ${renderValueSpan(value)}${duSuffix}`;
  }

  // ── Mode "f": formula only ──────────────────────────
  if (mode === "f") {
    if (!exprText || exprText === String(value) || /^[\d.]+$/.test(exprText)) {
      if (evaluator.isMatrix(value)) return `${nameHTML} = ${renderMatrixHTML(value, r.defaultUnit)}`;
      return `${nameHTML} = ${renderValueSpan(value)}${duSuffix}`;
    }
    return `${nameHTML} = ${renderMathExpr(exprText)}`;
  }

  // ── Mode "fr": formula + result (skip substitution) ─
  if (mode === "fr") {
    if (evaluator.isCellArray(value)) return `${nameHTML} = ${renderCellArrayHTML(value, varName)}`;
    if (evaluator.isMatrix(value)) {
      const matHTML = renderMatrixHTML(value, r.defaultUnit);
      const isMatLit = exprText && /^\[?\[[\d\s.,;\-+/*^eE]+\]\]?\s*\w*/.test(exprText);
      if (exprText && /[a-zA-Z]/.test(exprText) && !isMatLit) {
        return `${nameHTML} = ${renderMathExpr(exprText)} = ${matHTML}`;
      }
      return `${nameHTML} = ${matHTML}`;
    }
    const valueHTML = renderValueSpan(value);
    if (!exprText || exprText === String(value) || /^[\d.]+$/.test(exprText)) {
      return `${nameHTML} = ${valueHTML}${duSuffix}`;
    }
    return `${nameHTML} = ${renderMathExpr(exprText)} = ${valueHTML}${duSuffix}`;
  }

  // ── Default: full procedure ─────────────────────────

  // Si es un cell array, mostrar con formato especial
  if (evaluator.isCellArray(value)) {
    return `${nameHTML} = ${renderCellArrayHTML(value, varName)}`;
  }

  // Si es una matriz, mostrar nombre = expr simbolica = matriz numerica
  if (evaluator.isMatrix(value)) {
    // Skip symbolic expression when exprText is a matrix literal ([[...]])
    // — rendering it as text is ugly and redundant with the computed matrix
    const isMatLiteral = exprText && /^\[?\[[\d\s.,;\-+/*^eE]+\]\]?\s*\w*/.test(exprText);
    if (exprText && /[a-zA-Z]/.test(exprText) && !isMatLiteral) {
      const substituted = substituteValues(exprText, scope);
      // Solo mostrar sustitucion si difiere del resultado numerico
      const matHTML = renderMatrixHTML(value, r.defaultUnit);
      if (substituted) {
        const substHTML = renderMathExpr(substituted);
        if (substHTML !== matHTML) {
          return `${nameHTML} = ${renderMathExpr(exprText)} = ${substHTML} = ${matHTML}`;
        }
      }
      return `${nameHTML} = ${renderMathExpr(exprText)} = ${matHTML}`;
    }
    return `${nameHTML} = ${renderMatrixHTML(value, r.defaultUnit)}`;
  }

  // Renderizar valor
  const valueHTML = renderValueSpan(value);

  // Si la expresion es simple (solo un numero o variable), solo var = valor
  if (!exprText || exprText === String(value) || /^[\d.]+$/.test(exprText)) {
    return `${nameHTML} = ${valueHTML}${duSuffix}`;
  }

  // Unit literal: L = 5 cm, sigma = 250 MPa → suppress redundant "= 5 cm"
  // The expression "5 cm" renders as "5 · cm" and value renders as "5 cm" → redundant
  if (isUnitValue(value) && exprText) {
    // Check if RHS is a simple unit literal (number + unit name)
    if (/^\d+(\.\d+)?\s+[a-zA-Z]/.test(exprText.trim())) {
      return `${nameHTML} = ${valueHTML}`;
    }
    // Pipe conversion: L_2 = L_1|inch → show: L₂ = L₁ → 1.9685 inch
    if (exprText.includes("|") && !exprText.includes("||")) {
      const pipeIdx = exprText.indexOf("|");
      const srcExpr = exprText.slice(0, pipeIdx).trim();
      const tgtUnit = exprText.slice(pipeIdx + 1).trim();
      return `${nameHTML} = ${renderMathExpr(srcExpr)} \u2192 ${valueHTML}`;
    }
  }

  // Procedimiento: nombre = expr simbolica = expr con valores (con unidades) = resultado
  // Build annotated substitution with unit labels from varUnits or preStripDisplay
  const varUnits = evaluator.getVarUnits();
  let subOverrides: Map<string, number> | undefined;
  let subVarUnits: Map<string, string> | undefined;

  if (isUnitValue(value)) {
    // Pre-strip Unit result: use original display values & original units for substitution
    // e.g. I = b*h^3/12, b=30cm, h=60cm → show 30·60³/12 = 540000 cm⁴
    const preStrip = evaluator.getPreStripDisplay();
    if (preStrip.size > 0) {
      subOverrides = new Map<string, number>();
      subVarUnits = new Map<string, string>();
      for (const [k, info] of preStrip) {
        subOverrides.set(k, info.value);
        subVarUnits.set(k, info.unit);
      }
    }
  } else if (varUnits.size > 0) {
    // Post-strip result: use stripped scope values with target unit labels
    // e.g. EI = Ec*I → show 2188197.9 tonf/m² · 0.0054 m⁴ = 11816.27 tonf·m²
    subVarUnits = varUnits;
  }

  const subResult = substituteValuesAnnotated(exprText, scope, subVarUnits, subOverrides);
  if (subResult && subResult.text !== fmtNum(value)) {
    // Render the tokenized substitution through renderMathExpr, then inject unit annotations
    let substHTML = renderMathExpr(subResult.tokenized);
    substHTML = injectUnitAnnotations(substHTML, subResult.tokens);
    return `${nameHTML} = ${renderMathExpr(exprText)} = ${substHTML} = ${valueHTML}${duSuffix}`;
  }
  return `${nameHTML} = ${renderMathExpr(exprText)} = ${valueHTML}${duSuffix}`;
}

/** Renderiza una expresion pura (sin asignacion) */
function renderExprResult(r: LineResult): string {
  const duSuffix = r.defaultUnit ? `\u2006<i class="unit">${renderUnitLabel(r.defaultUnit)}</i>` : "";
  if (evaluator.isMatrix(r.value)) return renderMatrixHTML(r.value, r.defaultUnit);
  return renderValueSpan(r.value) + duSuffix;
}

/** Renderiza celdas @{cells} */
function renderCells(r: LineResult, dl = ""): string {
  if (!r.cells || r.cells.length === 0) return "";
  const scope = evaluator.getScope();
  const mode = r.cellsMode || r.displayMode; // inline mode takes priority over @{mode}
  const cellsHTML = r.cells.map(c => {
    const nameHTML = c.varName ? renderVarName(c.varName) : "";
    const valueHTML = renderValueSpan(c.value);
    const exprHTML = c.expr ? renderMathExpr(c.expr) : "";
    const isSimple = !c.expr || c.expr === String(c.value) || /^[\d.]+$/.test(c.expr);
    // Unit annotation suffix from & operator
    const uSuffix = c.unitAnnotation
      ? `\u2006<i class="unit">${renderUnitLabel(c.unitAnnotation)}</i>`
      : "";

    if (c.varName) {
      // Mode "r": result only → name = value
      if (mode === "r") {
        return `<span class="eq">${nameHTML} = ${valueHTML}${uSuffix}</span>`;
      }
      // Mode "f": formula only → name = symbolic expression
      if (mode === "f") {
        if (isSimple) return `<span class="eq">${nameHTML} = ${valueHTML}${uSuffix}</span>`;
        return `<span class="eq">${nameHTML} = ${exprHTML}${uSuffix}</span>`;
      }
      // Mode "fr": formula + result (skip substitution)
      if (mode === "fr") {
        if (isSimple) return `<span class="eq">${nameHTML} = ${valueHTML}${uSuffix}</span>`;
        return `<span class="eq">${nameHTML} = ${exprHTML} = ${valueHTML}${uSuffix}</span>`;
      }
      // Default: full procedure → name = formula = substitution = result
      if (isSimple) {
        return `<span class="eq">${nameHTML} = ${valueHTML}${uSuffix}</span>`;
      }
      const substituted = substituteValues(c.expr, scope);
      if (substituted && substituted !== fmtNum(c.value)) {
        return `<span class="eq">${nameHTML} = ${exprHTML} = ${renderMathExpr(substituted)} = ${valueHTML}${uSuffix}</span>`;
      }
      return `<span class="eq">${nameHTML} = ${exprHTML} = ${valueHTML}${uSuffix}</span>`;
    }
    return `<span class="eq">${valueHTML}${uSuffix}</span>`;
  });
  return `<div class="out-cells"${dl}>${cellsHTML.join("")}</div>`;
}

// ═══════════════════════════════════════════════════════════
// SUBSTITUCION DE VALORES (procedimiento)
// ═══════════════════════════════════════════════════════════

/** Palabras reservadas de math.js que NO son variables */
const MATH_KEYWORDS = new Set([
  'sqrt', 'sin', 'cos', 'tan', 'cot', 'sec', 'csc',
  'asin', 'acos', 'atan', 'atan2', 'log', 'ln', 'exp', 'abs',
  'det', 'inv', 'norm', 'dot', 'cross', 'transpose',
  'multiply', 'lusolve', 'add', 'subset', 'index', 'range',
  'matrix', 'col', 'row', 'pi', 'e', 'inf', 'true', 'false',
  'ceil', 'floor', 'round', 'sign', 'mod', 'min', 'max',
  'sum', 'prod', 'mean', 'trace', 'diag', 'zeros', 'ones', 'eye',
  'size', 'length', 'concat', 'flatten', 'reshape', 'sort',
]);

/**
 * Sustituye nombres de variables por sus valores numericos en una expresion.
 * Retorna null si no se sustituyo nada.
 */
function substituteValues(expr: string, scope: Record<string, any>): string | null {
  // Obtener variables escalares del scope, ordenadas por longitud (mas larga primero)
  const varNames = Object.keys(scope)
    .filter(v => !MATH_KEYWORDS.has(v) && typeof scope[v] === 'number')
    .sort((a, b) => b.length - a.length);

  let result = expr;
  let anyReplaced = false;

  for (const varName of varNames) {
    const value = scope[varName] as number;
    const escaped = varName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const regex = new RegExp(`\\b${escaped}\\b`, 'g');
    const before = result;
    const numStr = fmtNum(value);
    // Parentizar negativos para evitar ambiguedad: a*-3 -> a*(-3)
    const replacement = value < 0 ? `(${numStr})` : numStr;
    result = result.replace(regex, replacement);
    if (result !== before) anyReplaced = true;
  }

  return anyReplaced ? result : null;
}

/**
 * Substitutes variable names with numeric values AND inserts %%Un%% unit annotation tokens.
 * Tokens are placed after each substituted value that has a unit in varUnits,
 * EXCEPT when an exponent (^N) immediately follows the variable.
 * @param overrides Optional map of variable → number to use instead of scope values
 * @param varUnits Optional map of variable → unit string for annotations
 */
function substituteValuesAnnotated(
  expr: string,
  scope: Record<string, any>,
  varUnits?: Map<string, string>,
  overrides?: Map<string, number>
): { text: string; tokenized: string; tokens: Array<{ id: string; unit: string }> } | null {
  const varNames = Object.keys(scope)
    .filter(v => !MATH_KEYWORDS.has(v) && (typeof scope[v] === 'number' || overrides?.has(v)))
    .sort((a, b) => b.length - a.length);

  let result = expr;
  let anyReplaced = false;
  const tokens: Array<{ id: string; unit: string }> = [];
  let tokenId = 0;

  for (const varName of varNames) {
    const value = overrides?.get(varName) ?? scope[varName];
    if (typeof value !== 'number') continue;
    const escaped = varName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const regex = new RegExp(`\\b${escaped}\\b`, 'g');
    const before = result;
    const numStr = fmtNum(value);
    const unitStr = varUnits?.get(varName);

    result = result.replace(regex, (_match: string, offset: number, fullStr: string) => {
      const afterPos = offset + _match.length;
      const hasExponent = fullStr.charAt(afterPos) === '^';

      if (unitStr && !hasExponent) {
        const tok = `%%U${tokenId}%%`;
        tokens.push({ id: tok, unit: unitStr });
        tokenId++;
        return value < 0 ? `(${numStr})${tok}` : `${numStr}${tok}`;
      }
      return value < 0 ? `(${numStr})` : numStr;
    });
    if (result !== before) anyReplaced = true;
  }

  if (!anyReplaced) return null;

  // Plain text (without tokens) for comparison
  let text = result;
  for (const { id } of tokens) {
    text = text.replaceAll(id, '');
  }

  return { text, tokenized: result, tokens };
}

/**
 * Replaces %%Un%% tokens in rendered HTML with <span class="sub-unit"> unit labels.
 * Uses inline rendering (superscripts only, no fraction formatting) for compactness.
 */
function injectUnitAnnotations(html: string, tokens: Array<{ id: string; unit: string }>): string {
  let result = html;
  for (const { id, unit } of tokens) {
    // Apply display aliases (inch → in) then superscripts
    const aliased = applyUnitAlias(unit);
    const inlineUnit = aliased.replace(/\^(\d+)/g, '<sup>$1</sup>');
    const unitHTML = `<span class="sub-unit">\u2009${inlineUnit}</span>`;
    result = result.replaceAll(id, unitHTML);
  }
  return result;
}

// ═══════════════════════════════════════════════════════════
// GREEK LETTERS
// ═══════════════════════════════════════════════════════════

const GREEK: Record<string, string> = {
  alpha: "\u03B1", beta: "\u03B2", gamma: "\u03B3", delta: "\u03B4",
  epsilon: "\u03B5", zeta: "\u03B6", eta: "\u03B7", theta: "\u03B8",
  iota: "\u03B9", kappa: "\u03BA", lambda: "\u03BB", mu: "\u03BC",
  nu: "\u03BD", xi: "\u03BE", omicron: "\u03BF", pi: "\u03C0",
  rho: "\u03C1", sigma: "\u03C3", tau: "\u03C4", upsilon: "\u03C5",
  phi: "\u03C6", chi: "\u03C7", psi: "\u03C8", omega: "\u03C9",
  Alpha: "\u0391", Beta: "\u0392", Gamma: "\u0393", Delta: "\u0394",
  Epsilon: "\u0395", Zeta: "\u0396", Eta: "\u0397", Theta: "\u0398",
  Iota: "\u0399", Kappa: "\u039A", Lambda: "\u039B", Mu: "\u039C",
  Nu: "\u039D", Xi: "\u039E", Omicron: "\u039F", Pi: "\u03A0",
  Rho: "\u03A1", Sigma: "\u03A3", Tau: "\u03A4", Upsilon: "\u03A5",
  Phi: "\u03A6", Chi: "\u03A7", Psi: "\u03A8", Omega: "\u03A9",
};

/** Convierte nombre griego a su caracter Unicode */
function greekify(s: string): string {
  return GREEK[s] ?? s;
}

// ═══════════════════════════════════════════════════════════
// VARIABLE NAMES - <var> with <sub> for subscripts
// ═══════════════════════════════════════════════════════════

/** Renderiza nombre de variable: alpha_2 -> <var>α</var><sub>2</sub> */
function renderVarName(name: string): string {
  if (!name) return "";
  // Detect _prime → render as ′ (prime symbol) before the subscript
  let prime = "";
  let n = name;
  if (n.includes("_prime")) {
    prime = "\u2032"; // ′
    n = n.replace(/_prime/g, "_");
    // Clean double underscores: f__c → f_c
    n = n.replace(/__+/g, "_").replace(/^_|_$/g, "");
  }
  const parts = n.split("_");
  const base = greekify(parts[0]);
  if (parts.length <= 1 && !parts[1]) {
    return `<var>${escHtml(base)}${prime}</var>`;
  }
  const sub = parts.slice(1).filter(Boolean).map(p => greekify(p)).join("_");
  if (!sub) return `<var>${escHtml(base)}${prime}</var>`;
  return `<var>${escHtml(base)}${prime}</var><sub>${escHtml(sub)}</sub>`;
}

// ═══════════════════════════════════════════════════════════
// MATH EXPRESSION RENDERING
// ═══════════════════════════════════════════════════════════

/** Renderiza una expresion de matriz simbolica [[a],[b],[c]] como tabla vertical */
function renderSymbolicMatrix(expr: string): string | null {
  const t = expr.trim();
  if (!t.startsWith('[[') || !t.endsWith(']]')) return null;

  // Parsear filas respetando profundidad de brackets
  const inner = t.slice(1, -1); // quitar [ ] externo
  const rows: string[] = [];
  let depth = 0, current = '';
  for (let i = 0; i < inner.length; i++) {
    const ch = inner[i];
    if (ch === '[') depth++;
    else if (ch === ']') depth--;
    current += ch;
    if (depth === 0 && current.trim()) {
      const row = current.trim();
      if (row.startsWith('[') && row.endsWith(']')) {
        rows.push(row.slice(1, -1).trim());
      }
      current = '';
      // saltar coma despues de ]
      if (i + 1 < inner.length && inner[i + 1] === ',') i++;
    }
  }
  if (rows.length === 0) return null;

  // Detectar si es vector columna (1 elemento por fila) o matriz
  const isCol = rows.every(r => !r.includes(','));
  const cols = isCol ? 1 : (rows[0].split(',').length);

  let html = `<span class="matrix" style="--mat-cols:${cols}">`;
  for (const row of rows) {
    html += `<span class="tr"><span class="td"></span>`;
    if (isCol) {
      html += `<span class="td">${renderMathExpr(row)}</span>`;
    } else {
      for (const cell of row.split(',')) {
        html += `<span class="td">${renderMathExpr(cell.trim())}</span>`;
      }
    }
    html += `<span class="td"></span></span>`;
  }
  html += `</span>`;
  return html;
}

/** Renderiza una expresion matematica con formato visual */
function renderMathExpr(expr: string): string {
  // Detectar matrices [[...],[...]] y renderizar como tabla vertical
  const matHTML = renderSymbolicMatrix(expr);
  if (matHTML) return matHTML;

  let result = expr;

  // 0. Cell array / matrix bracket notation:
  //    k~{1} → [k̄]₁  (overbar + brackets + subscript)
  //    k{1}  → [k]₁   (brackets + subscript)
  //    K~{R} → [K̄]ᵣ   (overbar + brackets + subscript)
  //    K{R}  → [K]ᵣ   (brackets + subscript)
  result = result.replace(/\b([a-zA-Z]\w*)~\{(\w+)\}/g, (_, name, idx) => {
    return `[${renderVarName(name)}\u0304]<sub>${greekify(idx)}</sub>`;
  });
  result = result.replace(/\b([a-zA-Z]\w*)\{(\w+)\}/g, (_, name, idx) => {
    return `[${renderVarName(name)}]<sub>${greekify(idx)}</sub>`;
  });

  // 1. sqrt(expr) -> radical con clase .r0 + .o0 (SVG)
  if (renderCfg.sqrt) {
    result = result.replace(/sqrt\(([^)]+)\)/g, (_, inner) => {
      return `<span class="radical-wrap"><span class="r0"></span><span class="o0">${renderMathExpr(inner)}</span></span>`;
    });
  }

  // 2. Fraction rendering (when Fractions mode is on)
  if (getFractions()) {
    // 2a. (a+b)/(c-d) → fraction
    result = result.replace(/\(([^)]+)\)\s*\/\s*\(([^)]+)\)/g, (_, num, den) => {
      return `<span class="dvc"><span class="dvl">${renderMathExpr(num)}</span><span>${renderMathExpr(den)}</span></span>`;
    });
    // 2b. General division → fraction (when no top-level + or - remain)
    //     Split on first / not inside parentheses or HTML tags
    if (result.indexOf('/') >= 0 && !result.includes('class="dvc"')) {
      let depth = 0, slashIdx = -1, inTag = false;
      for (let ci = 0; ci < result.length; ci++) {
        const ch = result[ci];
        if (ch === '<') { inTag = true; continue; }
        if (ch === '>') { inTag = false; continue; }
        if (inTag) continue;
        if (ch === '(') depth++;
        else if (ch === ')') depth--;
        else if (ch === '/' && depth === 0) { slashIdx = ci; break; }
      }
      if (slashIdx > 0) {
        let num = result.slice(0, slashIdx).trim();
        let den = result.slice(slashIdx + 1).trim();
        if (num && den) {
          // Strip outer matching parens — fraction bar already provides grouping
          const stripOuter = (s: string): string => {
            if (s.startsWith('(') && s.endsWith(')')) {
              let d = 0;
              for (let i = 0; i < s.length - 1; i++) {
                if (s[i] === '(') d++;
                else if (s[i] === ')') d--;
                if (d === 0) return s; // parens don't match end
              }
              return s.slice(1, -1);
            }
            return s;
          };
          num = stripOuter(num);
          den = stripOuter(den);
          // Render num/den, then strip outer parens from rendered result
          // (fraction bar provides grouping, so (200·50) → 200·50 inside fraction)
          let rNum = renderMathExpr(num);
          let rDen = renderMathExpr(den);
          rNum = stripOuter(rNum);
          rDen = stripOuter(rDen);
          result = `<span class="dvc"><span class="dvl">${rNum}</span><span>${rDen}</span></span>`;
          return result; // already recursed
        }
      }
    }
  } else {
    // Fractions OFF: handled at the end (after multiplication step)
  }

  // 3. Funciones conocidas: sin, cos, etc -> <i>func</i>
  result = result.replace(/\b(sin|cos|tan|cot|sec|csc|asin|acos|atan|log|ln|exp|sqrt|abs|det|inv|norm|dot|cross|transpose|multiply|lusolve|add|subset|index|range|matrix)\b/g,
    '<i>$1</i>');

  // 4. Greek letter words -> Unicode (before splitting into single chars)
  result = result.replace(/\b(alpha|beta|gamma|delta|epsilon|zeta|eta|theta|iota|kappa|lambda|mu|nu|xi|omicron|pi|rho|sigma|tau|upsilon|phi|chi|psi|omega|Alpha|Beta|Gamma|Delta|Epsilon|Zeta|Eta|Theta|Iota|Kappa|Lambda|Mu|Nu|Xi|Omicron|Pi|Rho|Sigma|Tau|Upsilon|Phi|Chi|Psi|Omega)\b/g,
    (m) => `<var>${greekify(m)}</var>`);

  // 5. Variables con subindice: a_xyz -> <var>a</var><sub>xyz</sub>
  //    Handle _prime → ′ (prime symbol for ACI notation: f'c)
  if (renderCfg.sub) {
    result = result.replace(/\b([a-zA-Z][a-zA-Z0-9]*)_((?:prime_?)?\w*)\b/g, (_, base, sub) => {
      let prime = "";
      let cleanSub = sub;
      if (cleanSub.startsWith("prime")) {
        prime = "\u2032";
        cleanSub = cleanSub.replace(/^prime_?/, "");
      }
      if (!cleanSub) return `<var>${greekify(base)}${prime}</var>`;
      return `<var>${greekify(base)}${prime}</var><sub>${greekify(cleanSub)}</sub>`;
    });
  }

  // 6. Variables simples (letras solas que no son parte de tags HTML) -> <var>
  //    Lookbehind: skip letters preceded by < (opening tags) — \b handles </var> naturally
  //    Lookahead:  skip letters followed by > or ( (tag close or function call)
  result = result.replace(/(?<![<])\b([a-zA-Z])\b(?![>(<])/g, '<var>$1</var>');

  // 6. Smart multiplication rendering:
  if (renderCfg.mul) {
    // 6a. number * <var> → implicit juxtaposition (no dot): 2c, -2c, 12c
    result = result.replace(/(\d+(?:\.\d+)?)\s*\*\s*(<var>)/g, '$1$2');
    // 6b. </var|sub|sup> * <var> → implicit (variable × variable): EI, E_s·I_z
    result = result.replace(/(<\/(?:var|sub|sup)>)\s*\*\s*(<var>)/g, '$1$2');
    // 6c. number * number → parenthesized product: (2·306.936)
    //     negative lookahead: NOT when second number is followed by ^, digit, dot, or %
    //     (avoids breaking 0.1*100^2 and keeps %%Un%% unit tokens adjacent to their number)
    result = result.replace(/(-?\d+(?:\.\d+)?)\s*\*\s*(\d+(?:\.\d+)?)(?![0-9.^%])/g, '($1\u00B7$2)');
    // 6d. remaining * → ·
    result = result.replace(/\*/g, '\u00B7');
  }

  // 7. ^N -> <sup>N</sup>  (AFTER variables para que <var>a</var>^2 funcione)
  if (renderCfg.sup) {
    result = result.replace(/\^(\d+)/g, '<sup>$1</sup>');
    result = result.replace(/\^\{([^}]+)\}/g, '<sup>$1</sup>');
  }

  // 8. Fractions OFF: wrap (num)/(den) only when numeric expressions need grouping
  //    Pure variable expressions like EA/L stay as EA/L (no parens)
  //    Numeric expressions like (200·50)/6 get parens: (200·50)/(6)
  if (!renderCfg.frac && result.indexOf('/') >= 0 && !result.includes('class="dvc"')) {
    // Find first top-level / not inside parens or HTML tags
    let depth = 0, tagDepth = 0, slashIdx = -1;
    for (let ci = 0; ci < result.length; ci++) {
      const ch = result[ci];
      if (ch === '<') tagDepth++;
      else if (ch === '>') tagDepth--;
      else if (tagDepth === 0) {
        if (ch === '(') depth++;
        else if (ch === ')') depth--;
        else if (ch === '/' && depth === 0) { slashIdx = ci; break; }
      }
    }
    if (slashIdx > 0) {
      let num = result.slice(0, slashIdx).trim();
      let den = result.slice(slashIdx + 1).trim();
      if (num && den) {
        // Check if expression contains numbers (needs parens) vs pure variables (no parens)
        const hasNumbers = (s: string) => /\d/.test(s);
        if (hasNumbers(num) || hasNumbers(den)) {
          // Strip outer matching parens to avoid doubling
          const stripOuterParens = (s: string): string => {
            while (s.startsWith('(') && s.endsWith(')')) {
              let d = 0, matched = true;
              for (let i = 0; i < s.length - 1; i++) {
                if (s[i] === '<') { while (i < s.length && s[i] !== '>') i++; continue; }
                if (s[i] === '(') d++;
                else if (s[i] === ')') d--;
                if (d === 0 && i < s.length - 1) { matched = false; break; }
              }
              if (matched) s = s.slice(1, -1);
              else break;
            }
            return s;
          };
          num = stripOuterParens(num);
          den = stripOuterParens(den);
          result = `(${num})/(${den})`;
        }
        // Pure variables: leave as num/den without extra parens
      }
    }
  }

  return result;
}

/** Renderiza texto de comentario con formato math (subscripts, superscripts, griego) */
function renderCommentMath(text: string): string {
  let result = escHtml(text);

  // Cell/matrix bracket notation in comments:
  //   k~{1} → [k̄]₁,  k{1} → [k]₁,  KM_0{1} → [KM₀]₁
  result = result.replace(/\b([a-zA-Z]\w*)~\{(\w+)\}/g, (_, name, idx) => {
    return `[${renderVarName(name)}\u0304]<sub>${greekify(idx)}</sub>`;
  });
  result = result.replace(/\b([a-zA-Z]\w*)\{(\w+)\}/g, (_, name, idx) => {
    return `[${renderVarName(name)}]<sub>${greekify(idx)}</sub>`;
  });

  // Greek letter words -> Unicode
  result = result.replace(/\b(alpha|beta|gamma|delta|epsilon|zeta|eta|theta|iota|kappa|lambda|mu|nu|xi|omicron|rho|sigma|tau|upsilon|phi|chi|psi|omega|Alpha|Beta|Gamma|Delta|Epsilon|Zeta|Eta|Theta|Iota|Kappa|Lambda|Mu|Nu|Xi|Omicron|Rho|Sigma|Tau|Upsilon|Phi|Chi|Psi|Omega)\b/g,
    (m) => greekify(m));

  // Variables con subindice: X_abc -> X<sub>abc</sub>
  result = result.replace(/([a-zA-Z\u0370-\u03FF])_(\w+)/g, (_, base, sub) => {
    return `${base}<sub>${greekify(sub)}</sub>`;
  });

  // Superscripts: ^2, ^{n+1}
  result = result.replace(/\^(\d+)/g, '<sup>$1</sup>');
  result = result.replace(/\^\{([^}]+)\}/g, '<sup>$1</sup>');

  // * -> · (middle dot)
  result = result.replace(/\*/g, '\u00B7');

  return result;
}

// ═══════════════════════════════════════════════════════════
// VALUE RENDERING
// ═══════════════════════════════════════════════════════════

// ── Unit helpers ──────────────────────────────────────────

/** Check if a value is a math.js Unit object */
function isUnitValue(val: any): boolean {
  return val != null && typeof val === "object"
    && typeof val.toNumber === "function"
    && typeof val.formatUnits === "function";
}

/**
 * Get common unit string from a flat array of values.
 * Returns the unit string if ALL elements are Unit objects with the same unit,
 * or null otherwise (mixed types, different units, or plain numbers).
 */
function getCommonUnit(items: any[]): string | null {
  if (items.length === 0) return null;
  if (!isUnitValue(items[0])) return null;
  const unit: string = HekatanEvaluator.simplifyUnits(items[0].formatUnits());
  if (!unit) return null;
  for (let i = 1; i < items.length; i++) {
    if (!isUnitValue(items[i])) return null;
    if (HekatanEvaluator.simplifyUnits(items[i].formatUnits()) !== unit) return null;
  }
  return unit;
}

/**
 * Try to find a compatible unit: all cells are unit values and can be converted
 * to the same target unit (even if they have different string representations).
 * E.g. (GPa cm^2)/m and kN/m are the same dimension → convertible.
 * Returns { unit, values: number[] } or null.
 */
function getCompatibleUnit(items: any[]): { unit: string; values: number[] } | null {
  if (items.length === 0) return null;
  // All must be unit values
  for (const item of items) {
    if (!isUnitValue(item)) return null;
  }
  // Find a preferred target unit: pick the simplest one (shortest string) from non-zero cells
  let targetUnit: string | null = null;
  let shortest = Infinity;
  for (const item of items) {
    const u = item.formatUnits();
    if (u && item.toNumber() !== 0 && u.length < shortest) {
      shortest = u.length;
      targetUnit = u;
    }
  }
  if (!targetUnit) return null;
  // Try converting all cells to the target unit
  const values: number[] = [];
  for (const item of items) {
    try {
      const converted = item.to(targetUnit);
      values.push(converted.toNumber());
    } catch {
      return null; // incompatible dimensions
    }
  }
  return { unit: targetUnit, values };
}

/** Render a unit string with nice formatting (fractions, superscripts) */
/** Display aliases: math.js internal name → display abbreviation */
const UNIT_DISPLAY_ALIAS: Record<string, string> = {
  "inch": "in",
};

/** Apply display aliases to a unit string: "inch" → "in", "inch^4" → "in^4" */
function applyUnitAlias(unitStr: string): string {
  if (!unitStr) return unitStr;
  // Replace whole-word unit names with their aliases
  return unitStr.replace(/\b([a-zA-Z]+)(\^?\d*)/g, (_, base, exp) => {
    const alias = UNIT_DISPLAY_ALIAS[base] || base;
    return alias + exp;
  });
}

function renderUnitLabel(unitStr: string): string {
  // Apply display aliases first: "inch" → "in"
  const aliased = applyUnitAlias(unitStr);
  // IMPORTANT: find fraction "/" on the RAW string BEFORE adding <sup> tags,
  // so we don't confuse the "/" in "</sup>" with the unit division slash.
  const slashIdx = aliased.indexOf('/');
  const addSup = (s: string) => s.replace(/\^(\d+)/g, '<sup>$1</sup>');
  if (slashIdx >= 0) {
    const num = addSup(aliased.slice(0, slashIdx).trim());
    const den = addSup(aliased.slice(slashIdx + 1).trim());
    return `<span class="dvc">${num}<span class="dvl"></span>${den}</span>`;
  }
  return addSup(aliased);
}

/** Render a scalar Unit value: number + unit label */
function renderUnitScalar(val: any): string {
  const num = val.toNumber();
  const unit = HekatanEvaluator.simplifyUnits(val.formatUnits());
  const numStr = fmtNum(num);
  if (!unit) return numStr;
  return `${numStr}\u2006<i class="unit">${renderUnitLabel(unit)}</i>`;
}

/** Renderiza un valor numerico/escalar como span */
function renderValueSpan(value: any): string {
  if (value === undefined || value === null) return "";
  if (typeof value === "function") return "";

  // Cell array: { __cell: true, elements: [...] }
  if (value && value.__cell) {
    return renderCellArrayHTML(value);
  }

  // math.js Unit object (e.g. 5 cm, 250 MPa)
  if (isUnitValue(value)) {
    return renderUnitScalar(value);
  }

  if (evaluator.isMatrix(value)) {
    return renderMatrixHTML(value);
  }

  if (Array.isArray(value)) {
    // Check for per-row unit array from & [unit1, unit2, ...]
    const unitArray: string[] | undefined = (value as any).__commonUnitArray;
    if (unitArray) return renderVec1dHTML(value, undefined, unitArray);
    // Check for __commonUnit tag from tounit() conversion
    const taggedUnit = (value as any).__commonUnit;
    const commonUnit = taggedUnit || getCommonUnit(value);
    return renderVec1dHTML(value, commonUnit ?? undefined);
  }

  if (typeof value === "number") {
    return fmtNum(value);
  }

  return escHtml(String(value));
}

/** Renderiza un cell array: k = {[k]₁, [k]₂} (notacion corchetes, sin expandir) */
function renderCellArrayHTML(value: any, varName?: string): string {
  if (!value || !(value as any).__cell) return renderValueSpan(value);
  const elems = (value as any).elements as any[];
  const parts = elems.map((e: any, i: number) => {
    if (varName) {
      // Notacion con corchetes: [k]₁, [k]₂ — igual que acceso k{1}
      const base = greekify(varName.split("_")[0]);
      const varSub = varName.includes("_") ? `<sub>${escHtml(varName.split("_").slice(1).join("_"))}</sub>` : "";
      return `<span class="cell-element"><span class="cell-label"><span class="idx-br">[</span><var>${escHtml(base)}</var>${varSub}<span class="idx-br">]</span><sub>${i + 1}</sub></span></span>`;
    }
    // Sin varName → mostrar valor completo
    const valHTML = evaluator.isMatrix(e) ? renderMatrixHTML(e) : renderValueSpan(e);
    return `<span class="cell-element">${valHTML}</span>`;
  });
  const sep = varName
    ? '<span class="cell-sep"></span>'                  // sin coma en notacion [k]₁ [k]₂
    : '<span class="cell-sep">,</span>';                // con coma para valores literales
  return `<span class="cell-array"><span class="cell-brace">{</span>${parts.join(sep)}<span class="cell-brace">}</span></span>`;
}

/** Renderiza una matriz math.js usando clases .matrix .tr .td de template.html.
 *  Matrices grandes se truncan estilo Mathcad con indices y puntos suspensivos.
 *  El contenedor es resizable: el usuario puede estirar para ver mas/menos celdas. */
const MAT_MAX_VEC_ROWS = 12;   // max filas visibles para vectores columna
const MAT_MAX_ROWS = 8;        // max filas visibles para matrices 2D
const MAT_MAX_COLS = 8;        // max columnas visibles para matrices 2D

// Almacen global de datos de matrices para resize interactivo
const _matStore = new Map<string, { rows: any[][]; totalR: number; totalC: number; isVec: boolean; isRowVec?: boolean }>();
let _matIdCounter = 0;
/** Global visible rows/cols for truncated matrices. 0 = show all. Set from #matVisSelect. */
let _matVisSize = 3;

/** Renderiza un array 1D como vector columna (tabla vertical con corchetes).
 *  Para 1-2 elementos se renderiza inline [a, b]. Para 3+ se usa tabla vertical.
 *  unitArray: per-row units from & [unit1, unit2, ...] — renders unit next to each row. */
function renderVec1dHTML(items: any[], unitLabel?: string, unitArray?: string[]): string {
  const fmtItem = (v: any) => isUnitValue(v) ? renderUnitScalar(v) : fmtNum(v);
  const fmtCell = unitLabel
    ? (v: any) => fmtNum(isUnitValue(v) ? v.toNumber() : v)
    : fmtItem;

  // 1-2 elements: inline
  if (items.length <= 2 && !unitArray) {
    const inner = items.map(v => fmtCell(v)).join(", ");
    if (unitLabel) return `[${inner}]\u2006<i class="unit">${renderUnitLabel(unitLabel)}</i>`;
    return `[${inner}]`;
  }

  // 3+ elements: use mat-trunc format with truncation (same as large matrices)
  const n = items.length;
  const visR = _matVisSize === 0 ? n : Math.min(_matVisSize, n);

  // Convert 1D items to 2D column vector for _buildTruncatedMatrixHTML
  // Extract numeric values when units are factored out
  const numItems = unitLabel
    ? items.map(v => isUnitValue(v) ? v.toNumber() : v)
    : items;
  const rows2d: any[][] = numItems.map(v => [v]);
  const matId = `mat-${_matIdCounter++}`;
  _matStore.set(matId, { rows: rows2d, totalR: n, totalC: 1, isVec: true });
  // Store formatter for resize handler
  (_matStore.get(matId) as any).cellFmt = fmtCell;

  const html = _buildTruncatedMatrixHTML(matId, rows2d, n, 1, true, false, visR, 1, fmtCell, unitArray);

  if (!unitArray && unitLabel) {
    return `<span class="mat-with-unit">${html}<span class="mat-unit-sticky">\u2006<i class="unit">${renderUnitLabel(unitLabel)}</i></span></span>`;
  }
  return html;
}

function renderMatrixHTML(m: any, defaultUnit?: string): string {
  // Use _data directly when available — toArray() corrupts when DenseMatrix holds Unit objects.
  // DenseMatrix with Units often gets shape [1,N,M] instead of [N,M]; unwrap the extra dimension.
  let arr: any[];
  const rawData = (m as any)._data;
  if (rawData) {
    const sz = m.size();
    arr = (sz.length === 3 && sz[0] === 1 && Array.isArray(rawData[0])) ? rawData[0] : rawData;
  } else {
    arr = m.toArray() as any[];
  }

  // Check for per-row unit array from & [unit1, unit2, ...]
  const taggedUnitArray: string[] | undefined = (m as any).__commonUnitArray;

  // Check for __commonUnit tag from tounit() conversion
  const taggedUnit: string | undefined = (m as any).__commonUnit;

  // Vector 1D: [a, b, c]
  if (!Array.isArray(arr[0])) {
    if (taggedUnitArray) return renderVec1dHTML(arr, undefined, taggedUnitArray);
    let commonUnit = taggedUnit || getCommonUnit(arr);
    if (!commonUnit) {
      const compat = getCompatibleUnit(arr);
      if (compat) {
        // Convert to compatible unit and render with that unit
        return renderVec1dHTML(compat.values, compat.unit);
      }
    }
    return renderVec1dHTML(arr, commonUnit ?? undefined);
  }

  const rows = arr as any[][];
  const totalR = rows.length;
  const totalC = rows[0]?.length ?? 1;
  const isColVec = totalC === 1;        // vector columna Nx1
  const isRowVec = totalR === 1;        // vector fila 1xN

  // Check for common unit: first from tounit() tag, then from cell inspection
  const allCells: any[] = [];
  for (const row of rows) for (const cell of row) allCells.push(cell);
  let matCommonUnit = taggedUnit || getCommonUnit(allCells) || defaultUnit;
  let convertedRows = rows;

  // If no exact common unit, try compatible unit conversion
  // (e.g. (GPa cm^2)/m and kN/m are the same dimension)
  if (!matCommonUnit) {
    const compat = getCompatibleUnit(allCells);
    if (compat) {
      matCommonUnit = compat.unit;
      // Rebuild rows with converted numeric values
      convertedRows = [];
      let idx = 0;
      for (let r = 0; r < totalR; r++) {
        const newRow: any[] = [];
        for (let c = 0; c < totalC; c++) {
          newRow.push(compat.values[idx++]);
        }
        convertedRows.push(newRow);
      }
    }
  }

  // Cell formatter: strip units for clean matrix display.
  // .toNumber() returns the value in the ORIGINAL unit representation (not SI base).
  // Matrices with mixed dimensions (e.g. stiffness: kN/m + kN·m) show only numbers —
  // per-cell units make the matrix unreadable. This matches Mathcad behavior.
  const fmtCell = (v: any) => fmtNum(isUnitValue(v) ? v.toNumber() : v);

  // Threshold: truncar desde 3 filas/columnas (mat-trunc format)
  const useTrunc = totalR >= 3 || totalC >= 3;

  if (!useTrunc) {
    // Renderizado normal para matrices pequeñas (1x1, 1x2, 2x1, 2x2)
    let html = `<span class="matrix" style="--mat-cols:${totalC}">`;
    for (const row of convertedRows) {
      html += `<span class="tr"><span class="td"></span>`;
      for (const v of row) html += `<span class="td">${fmtCell(v)}</span>`;
      html += `<span class="td"></span></span>`;
    }
    html += `</span>`;
    if (matCommonUnit) {
      return `<span class="mat-with-unit">${html}<span class="mat-unit-sticky">\u2006<i class="unit">${renderUnitLabel(matCommonUnit)}</i></span></span>`;
    }
    return html;
  }

  // mat-trunc format: visR/visC from selector, 0 = show all
  const matId = `mat-${_matIdCounter++}`;
  _matStore.set(matId, { rows: convertedRows, totalR, totalC, isVec: isColVec, isRowVec });

  const visR = _matVisSize === 0 ? totalR : Math.min(_matVisSize, totalR);
  const visC = isColVec ? 1 : (_matVisSize === 0 ? totalC : Math.min(_matVisSize, totalC));

  // Store formatter for resize handler
  const store = _matStore.get(matId)!;
  (store as any).cellFmt = fmtCell;

  const uArr = (taggedUnitArray && taggedUnitArray.length > 0 && isColVec) ? taggedUnitArray : undefined;
  let html = _buildTruncatedMatrixHTML(matId, convertedRows, totalR, totalC, isColVec, isRowVec, visR, visC, fmtCell, uArr);
  if (!uArr && matCommonUnit) {
    html = `<span class="mat-with-unit">${html}<span class="mat-unit-sticky">\u2006<i class="unit">${renderUnitLabel(matCommonUnit)}</i></span></span>`;
  }
  return html;
}

/** Genera el HTML truncado de una matriz. Separado para reusar en resize.
 *  Usa un CSS Grid plano: columna 0 = row-idx, columnas 1..N = data.
 *  Los indices quedan FUERA de los corchetes (mat-bracket absoluto).
 *  Soporta: col-vector (Nx1), row-vector (1xN), y matrices generales.
 *  cellFmt: optional cell formatter (default: fmtNum). Used to handle Unit values. */

function _buildTruncatedMatrixHTML(
  matId: string, rows: any[][], totalR: number, totalC: number,
  isColVec: boolean, isRowVec: boolean, visR: number, visC: number,
  cellFmt?: (v: any) => string, unitArray?: string[]
): string {
  const fmt = cellFmt || fmtNum;
  const truncR = visR < totalR - 1;
  const truncC = visC < totalC - 1;
  const hasUnits = unitArray && unitArray.length > 0;

  // Columnas de datos
  let dataCols = isColVec ? 1 : visC;
  if (truncC) dataCols += 2; // dots + last

  // Row-vector: no row-idx column, solo col-idx header
  // Col-vector: no col-idx header, solo row-idx column
  // Matrix: ambos
  const hasRowIdx = !isRowVec;  // col izquierda con indices de fila
  const hasColHdr = !isColVec;  // fila superior con indices de columna

  // Grid columns: [row-idx?] + dataCols [+ unit-col?]
  let gridColsDef = hasRowIdx
    ? `auto repeat(${dataCols}, auto)`
    : `repeat(${dataCols}, auto)`;
  if (hasUnits) gridColsDef += ' auto'; // extra column for per-row units

  // Filas de display
  let dataRows = visR + (truncR ? 2 : 0);
  const totalDisplayRows = (hasColHdr ? 1 : 0) + dataRows;

  // Bracket position (grid lines, 1-based) — bracket should NOT cover unit column
  const bracketColStart = hasRowIdx ? 2 : 1;
  const bracketColEnd = (hasRowIdx ? 1 : 0) + dataCols + 1; // end before unit col
  const bracketRowStart = hasColHdr ? 2 : 1;

  let html = `<span class="mat-trunc" data-mat-id="${matId}" `
           + `data-vis-rows="${visR}" data-vis-cols="${visC}" `
           + (isColVec ? 'data-is-vec="1" ' : '')
           + (isRowVec ? 'data-is-rowvec="1" ' : '')
           + `style="grid-template-columns: ${gridColsDef}; `
           + `grid-template-rows: repeat(${totalDisplayRows}, auto);">`;

  // Fila header con indices de columna
  if (hasColHdr) {
    if (hasRowIdx) html += `<span class="mat-hdr-corner"></span>`;
    for (let c = 0; c < visC; c++)
      html += `<span class="mat-col-idx">${c + 1}</span>`;
    if (truncC) {
      html += `<span class="mat-col-idx mat-dots">\u22EF</span>`;
      html += `<span class="mat-col-idx">${totalC}</span>`;
    }
    if (hasUnits) html += `<span class="mat-hdr-corner"></span>`; // empty header for unit col
  }

  // Filas de datos
  for (let r = 0; r < visR; r++) {
    if (hasRowIdx) html += `<span class="mat-row-idx">${r + 1}</span>`;
    if (isColVec) {
      html += `<span class="mat-cell">${fmt(rows[r][0])}</span>`;
    } else {
      for (let c = 0; c < visC; c++)
        html += `<span class="mat-cell">${fmt(rows[r][c])}</span>`;
      if (truncC) {
        html += `<span class="mat-cell mat-dots">\u22EF</span>`;
        html += `<span class="mat-cell">${fmt(rows[r][totalC - 1])}</span>`;
      }
    }
    if (hasUnits) {
      const u = unitArray![r] || unitArray![unitArray!.length - 1] || '';
      html += `<span class="mat-row-unit"><i class="unit">${renderUnitLabel(u)}</i></span>`;
    }
  }

  // Fila de puntos suspensivos
  if (truncR) {
    if (hasRowIdx) html += `<span class="mat-row-idx mat-dots">\u22EE</span>`;
    if (isColVec) {
      html += `<span class="mat-cell mat-dots">\u22EE</span>`;
    } else {
      for (let c = 0; c < visC; c++)
        html += `<span class="mat-cell mat-dots">\u22EE</span>`;
      if (truncC) {
        html += `<span class="mat-cell mat-dots">\u22F1</span>`;
        html += `<span class="mat-cell mat-dots">\u22EE</span>`;
      }
    }
    if (hasUnits) html += `<span class="mat-row-unit mat-dots">\u22EE</span>`;
  }

  // Ultima fila
  if (truncR) {
    const lr = totalR - 1;
    if (hasRowIdx) html += `<span class="mat-row-idx">${totalR}</span>`;
    if (isColVec) {
      html += `<span class="mat-cell">${fmt(rows[lr][0])}</span>`;
    } else {
      for (let c = 0; c < visC; c++)
        html += `<span class="mat-cell">${fmt(rows[lr][c])}</span>`;
      if (truncC) {
        html += `<span class="mat-cell mat-dots">\u22EF</span>`;
        html += `<span class="mat-cell">${fmt(rows[lr][totalC - 1])}</span>`;
      }
    }
    if (hasUnits) {
      const u = unitArray![lr] || unitArray![unitArray!.length - 1] || '';
      html += `<span class="mat-row-unit"><i class="unit">${renderUnitLabel(u)}</i></span>`;
    }
  }

  // Bracket: abs-positioned sobre area de datos (excluding unit column)
  html += `<span class="mat-bracket" style="grid-column:${bracketColStart}/${bracketColEnd}; grid-row:${bracketRowStart}/-1;"></span>`;

  // Grip de resize
  html += `<span class="mat-grip" title="Arrastrar para ver mas/menos celdas"></span>`;
  return html + `</span>`;
}

// ─── Resize interactivo de matrices truncadas ────────────
(function initMatrixResize() {
  let dragState: {
    matEl: HTMLElement;
    matId: string;
    startX: number;
    startY: number;
    startVisR: number;
    startVisC: number;
    cellW: number;
    cellH: number;
  } | null = null;

  output.addEventListener("mousedown", (e) => {
    const grip = (e.target as HTMLElement).closest?.(".mat-grip");
    if (!grip) return;
    const matEl = grip.closest(".mat-trunc") as HTMLElement;
    if (!matEl) return;
    const matId = matEl.dataset.matId || "";
    const data = _matStore.get(matId);
    if (!data) return;

    e.preventDefault();
    e.stopPropagation();

    // Estimar tamaño de celda a partir del primer dato visible
    const firstTd = matEl.querySelector(".mat-cell:not(.mat-dots)");
    const cellRect = firstTd?.getBoundingClientRect();
    const cellW = cellRect?.width || 18;
    const cellH = cellRect?.height || 16;

    dragState = {
      matEl,
      matId,
      startX: e.clientX,
      startY: e.clientY,
      startVisR: parseInt(matEl.dataset.visRows || "8"),
      startVisC: parseInt(matEl.dataset.visCols || "8"),
      cellW,
      cellH,
    };
    matEl.classList.add("mat-resizing");
  });

  document.addEventListener("mousemove", (e) => {
    if (!dragState) return;
    e.preventDefault();
    const dx = e.clientX - dragState.startX;
    const dy = e.clientY - dragState.startY;
    const data = _matStore.get(dragState.matId);
    if (!data) return;

    // Calcular nuevas dimensiones visibles
    const newVisR = data.isRowVec ? 1 : Math.max(2, Math.min(data.totalR, dragState.startVisR + Math.round(dy / dragState.cellH)));
    const newVisC = data.isVec ? 1 : Math.max(2, Math.min(data.totalC, dragState.startVisC + Math.round(dx / dragState.cellW)));
    const curR = parseInt(dragState.matEl.dataset.visRows || "0");
    const curC = parseInt(dragState.matEl.dataset.visCols || "0");

    if (newVisR !== curR || newVisC !== curC) {
      // Re-render con nuevas dimensiones (use stored cellFmt if available)
      const newHTML = _buildTruncatedMatrixHTML(
        dragState.matId, data.rows, data.totalR, data.totalC, data.isVec, !!data.isRowVec, newVisR, newVisC, (data as any).cellFmt
      );
      const tmp = document.createElement("div");
      tmp.innerHTML = newHTML;
      const newEl = tmp.firstElementChild as HTMLElement;
      newEl.classList.add("mat-resizing");
      dragState.matEl.replaceWith(newEl);
      dragState.matEl = newEl;
    }
  });

  document.addEventListener("mouseup", () => {
    if (dragState) {
      dragState.matEl.classList.remove("mat-resizing");
      dragState = null;
    }
  });
})();

/** Formatea un numero */
function fmtNum(v: any): string {
  if (typeof v === "number") {
    if (Number.isInteger(v)) return String(v);
    const raw = parseInt(decimalsInput?.value);
    const dec = isNaN(raw) ? 2 : raw;
    // Very small numbers → use toPrecision to preserve significant digits
    // (toFixed truncates e.g. 0.0054 → "0.01" with dec=2, making equations inconsistent)
    if (dec > 0 && Math.abs(v) < Math.pow(10, -dec) && v !== 0) {
      return parseFloat(v.toPrecision(Math.max(dec, 2))).toString();
    }
    return parseFloat(v.toFixed(dec)).toString();
  }
  return escHtml(String(v));
}

// (Duplicate fontSize zoom handler removed — zoom is synced from MathCanvas)

// ─── Splitter drag to resize ─────────────────────────────
const splitter = document.getElementById("splitter") as HTMLDivElement;
const editorPanel = document.querySelector(".editor-panel") as HTMLDivElement;

splitter.addEventListener("mousedown", (e) => {
  e.preventDefault();
  splitter.classList.add("dragging");
  const parent = splitter.parentElement!;

  let rafId = 0;
  const onMove = (ev: MouseEvent) => {
    const rect = parent.getBoundingClientRect();
    const x = ev.clientX - rect.left;
    const pct = Math.max(15, Math.min(85, (x / rect.width) * 100));
    editorPanel.style.flexBasis = `${pct}%`;
    // Wait for DOM reflow before re-rendering
    cancelAnimationFrame(rafId);
    rafId = requestAnimationFrame(() => {
      editor.resize();
      syncZoom();
    });
  };

  const onUp = () => {
    splitter.classList.remove("dragging");
    document.removeEventListener("mousemove", onMove);
    document.removeEventListener("mouseup", onUp);
    cancelAnimationFrame(rafId);
    // Final re-render after drag ends (DOM already reflowed)
    requestAnimationFrame(() => {
      editor.resize();
      syncZoom();
    });
  };

  document.addEventListener("mousemove", onMove);
  document.addEventListener("mouseup", onUp);
});

// ─── Custom Scrollbar for Output Panel ────────────────────
(() => {
  const scrollContent = output;  // .output-content
  const scrollbar = document.getElementById("customScrollbar") as HTMLDivElement;
  const thumb = document.getElementById("scrollThumb") as HTMLDivElement;
  const btnUp = document.getElementById("scrollUp") as HTMLDivElement;
  const btnDown = document.getElementById("scrollDown") as HTMLDivElement;
  if (!scrollbar || !thumb || !btnUp || !btnDown) return;

  const BTN_H = 18;  // height of up/down buttons

  function updateThumb() {
    const { scrollHeight, clientHeight, scrollTop } = scrollContent;
    if (scrollHeight <= clientHeight) {
      scrollbar.style.display = "none";
      return;
    }
    scrollbar.style.display = "";
    // Position scrollbar to start below output-header
    const outputHeader = scrollContent.previousElementSibling as HTMLElement;
    const headerH = outputHeader ? outputHeader.offsetHeight : 0;
    scrollbar.style.top = headerH + "px";

    const trackH = scrollbar.clientHeight - BTN_H * 2;
    const ratio = clientHeight / scrollHeight;
    const thumbH = Math.max(30, trackH * ratio);
    const scrollRange = scrollHeight - clientHeight;
    const thumbTop = BTN_H + (scrollTop / scrollRange) * (trackH - thumbH);
    thumb.style.height = thumbH + "px";
    thumb.style.top = thumbTop + "px";
  }

  scrollContent.addEventListener("scroll", updateThumb);
  new ResizeObserver(updateThumb).observe(scrollContent);
  // Also update when content changes
  new MutationObserver(updateThumb).observe(scrollContent, { childList: true, subtree: true });

  // Drag thumb
  let dragging = false;
  let dragStartY = 0;
  let dragStartScroll = 0;

  thumb.addEventListener("mousedown", (e) => {
    e.preventDefault();
    dragging = true;
    dragStartY = e.clientY;
    dragStartScroll = scrollContent.scrollTop;
    thumb.classList.add("dragging");
  });

  document.addEventListener("mousemove", (e) => {
    if (!dragging) return;
    const { scrollHeight, clientHeight } = scrollContent;
    const trackH = scrollbar.clientHeight - BTN_H * 2;
    const ratio = clientHeight / scrollHeight;
    const thumbH = Math.max(30, trackH * ratio);
    const dy = e.clientY - dragStartY;
    const scrollRange = scrollHeight - clientHeight;
    const scrollDelta = (dy / (trackH - thumbH)) * scrollRange;
    scrollContent.scrollTop = dragStartScroll + scrollDelta;
  });

  document.addEventListener("mouseup", () => {
    if (dragging) {
      dragging = false;
      thumb.classList.remove("dragging");
    }
  });

  // Click on track to jump
  scrollbar.addEventListener("mousedown", (e) => {
    if (e.target === thumb || e.target === btnUp || e.target === btnDown) return;
    const rect = scrollbar.getBoundingClientRect();
    const clickY = e.clientY - rect.top - BTN_H;
    const { scrollHeight, clientHeight } = scrollContent;
    const trackH = scrollbar.clientHeight - BTN_H * 2;
    const ratio = clickY / trackH;
    scrollContent.scrollTop = ratio * (scrollHeight - clientHeight);
  });

  // Up/Down buttons
  let scrollInterval: number | null = null;
  const startScroll = (dir: number) => {
    scrollContent.scrollBy({ top: dir * 60 });
    scrollInterval = window.setInterval(() => scrollContent.scrollBy({ top: dir * 60 }), 120);
  };
  const stopScroll = () => { if (scrollInterval !== null) { clearInterval(scrollInterval); scrollInterval = null; } };

  btnUp.addEventListener("mousedown", (e) => { e.stopPropagation(); startScroll(-1); });
  btnDown.addEventListener("mousedown", (e) => { e.stopPropagation(); startScroll(1); });
  document.addEventListener("mouseup", stopScroll);

  // Initial state
  updateThumb();
})();

// ═══════════════════════════════════════════════════════════
// DEBUG CLI PANEL - Testing interactivo del MathEditor
// ═══════════════════════════════════════════════════════════
{
  const debugPanel = document.getElementById("debugPanel") as HTMLDivElement;
  const debugOutput = document.getElementById("debugOutput") as HTMLDivElement;
  const debugInput = document.getElementById("debugInput") as HTMLInputElement;
  const debugToggle = document.getElementById("debugToggle") as HTMLButtonElement;
  const btnDebug = document.getElementById("btnDebug") as HTMLButtonElement;

  let debugVisible = false;
  const cmdHistory: string[] = [];
  let histIdx = -1;

  function toggleDebug() {
    debugVisible = !debugVisible;
    debugPanel.style.display = debugVisible ? "flex" : "none";
    if (debugVisible) {
      debugInput.focus();
      dbgPrint("help", "Escribe 'help' para ver comandos disponibles");
    }
  }

  btnDebug.addEventListener("click", toggleDebug);
  debugToggle.addEventListener("click", toggleDebug);

  // F12 para toggle (no interfiere con DevTools si ctrl+shift+I)
  document.addEventListener("keydown", (e) => {
    if (e.key === "F12" && !e.ctrlKey && !e.shiftKey) {
      e.preventDefault();
      toggleDebug();
    }
  });

  function dbgPrint(cls: string, text: string, copyable?: string) {
    const line = document.createElement("div");
    line.className = "dbg-line dbg-" + cls;
    line.textContent = text;
    if (copyable) {
      const btn = document.createElement("span");
      btn.className = "dbg-copy";
      btn.textContent = "[copiar]";
      btn.title = "Copiar al portapapeles";
      btn.addEventListener("click", () => {
        navigator.clipboard.writeText(copyable).then(() => {
          btn.textContent = "[copiado!]";
          setTimeout(() => btn.textContent = "[copiar]", 1500);
        });
      });
      line.appendChild(btn);
    }
    debugOutput.appendChild(line);
    debugOutput.scrollTop = debugOutput.scrollHeight;
  }

  function dbgJSON(obj: any) {
    const json = JSON.stringify(obj, null, 2);
    dbgPrint("data", json, json);
  }

  function execDebugCmd(raw: string) {
    const input = raw.trim();
    if (!input) return;

    cmdHistory.push(input);
    histIdx = cmdHistory.length;
    dbgPrint("cmd", "> " + input);

    const parts = input.split(/\s+/);
    const cmd = parts[0].toLowerCase();
    const args = parts.slice(1);

    try {
      switch (cmd) {
        case "help":
        case "h":
        case "?":
          dbgPrint("help", "=== MathEditor Debug CLI ===");
          dbgPrint("help", "── Navegacion ──");
          dbgPrint("help", "info / i          - Estado actual del editor");
          dbgPrint("help", "pos / p           - Posicion del cursor con coordenadas");
          dbgPrint("help", "chars / ch        - Coordenadas pixel de cada caracter");
          dbgPrint("help", "elements / el [r] - Lista elementos en fila r");
          dbgPrint("help", "rows              - Lista todas las filas");
          dbgPrint("help", "left / l [N]      - Mover cursor izquierda N veces");
          dbgPrint("help", "right / r [N]     - Mover cursor derecha N veces");
          dbgPrint("help", "up / u            - Mover cursor arriba");
          dbgPrint("help", "down / d          - Mover cursor abajo");
          dbgPrint("help", "goto R C [P]      - Ir a fila R, columna C, posicion P");
          dbgPrint("help", "click X Y         - Simular click en canvas (X,Y)");
          dbgPrint("help", "── Edicion ──");
          dbgPrint("help", "type TEXTO        - Insertar texto");
          dbgPrint("help", "del [N]           - Borrar N caracteres (backspace)");
          dbgPrint("help", "line TEXTO        - Insertar nueva fila con texto");
          dbgPrint("help", "text              - Mostrar texto del elemento actual");
          dbgPrint("help", "all               - Serializar contenido completo");
          dbgPrint("help", "── Estructuras matematicas ──");
          dbgPrint("help", "frac [num] [den]  - Insertar fraccion");
          dbgPrint("help", "pow [base] [exp]  - Insertar potencia/superindice");
          dbgPrint("help", "sub [base] [sub]  - Insertar subindice");
          dbgPrint("help", "sqrt [expr]       - Insertar raiz cuadrada");
          dbgPrint("help", "int [lo] [hi] [f] - Insertar integral");
          dbgPrint("help", "deriv [f] [var]   - Insertar derivada");
          dbgPrint("help", "mat [R] [C]       - Insertar matriz RxC");
          dbgPrint("help", "vec [v1] [v2] ... - Insertar vector columna");
          dbgPrint("help", "── Ventana ──");
          dbgPrint("help", "new               - Nueva hoja en blanco");
          dbgPrint("help", "examples          - Listar ejemplos disponibles");
          dbgPrint("help", "load NOMBRE       - Cargar ejemplo por nombre");
          dbgPrint("help", "mode canvas|code  - Cambiar modo editor");
          dbgPrint("help", "preset NAME       - Cambiar preset (hekatan|latex|gabriola|mathcad|classic|black|dark)");
          dbgPrint("help", "preset next/prev  - Siguiente/anterior preset");
          dbgPrint("help", "preset cycle [seg]- Ciclar todos los presets");
          dbgPrint("help", "fonttext NAME     - Fuente texto (segoeui|georgia|tahoma|cambria|times)");
          dbgPrint("help", "fontexpr NAME     - Fuente expr (stix|cambria|gabriola|georgiapro|century)");
          dbgPrint("help", "color NAME        - Modo color (classic|black|dark)");
          dbgPrint("help", "autorun on|off    - Toggle AutoRun");
          dbgPrint("help", "run               - Ejecutar codigo (F5)");
          dbgPrint("help", "── Debug ──");
          dbgPrint("help", "clicklog on|off   - Log coordenadas al hacer click");
          dbgPrint("help", "bounds [row]      - Mostrar bounds de elementos");
          dbgPrint("help", "── Sistema ──");
          dbgPrint("help", "eval              - Forzar evaluacion");
          dbgPrint("help", "render            - Re-render canvas");
          dbgPrint("help", "focus             - Focus canvas + cursor timer");
          dbgPrint("help", "test              - Ejecutar test completo automatizado");
          dbgPrint("help", "clear / cls       - Limpiar consola");
          break;

        case "info":
        case "i": {
          const info = editor.getDebugInfo();
          dbgPrint("info", `Cursor: fila=${info.row} col=${info.col} | fontSize=${info.fontSize.toFixed(2)}px | zoom=${info.zoomLevel}`);
          dbgPrint("info", `Canvas: ${info.canvasW}x${info.canvasH}px | scroll=${info.scrollY} | contentH=${info.contentHeight}`);
          dbgPrint("info", `Timer: ${info.cursorTimer ? 'ON' : 'OFF'} | Visible: ${info.cursorVisible}`);
          if (info.element) {
            const e = info.element;
            dbgPrint("ok", `Elemento: ${e.type} @ (${e.x}, ${e.y}) size=${e.width}x${e.height}`);
            if (e.text !== undefined) {
              dbgPrint("ok", `Texto: "${e.text}" | display: "${e.displayText}" | cursorPos=${e.cursorPosition}/${e.textLength}`);
            }
          }
          const json = JSON.stringify(info, null, 2);
          dbgPrint("data", "JSON completo:", json);
          break;
        }

        case "pos":
        case "p": {
          const info = editor.getDebugInfo();
          if (info.element) {
            const e = info.element;
            const msg = `[${info.row},${info.col}] ${e.type} pos=${e.cursorPosition ?? '?'} @ pixel(${e.x}, ${e.y}) size(${e.width}x${e.height})`;
            dbgPrint("ok", msg, msg);
          } else {
            dbgPrint("err", "No hay elemento activo");
          }
          break;
        }

        case "chars":
        case "ch": {
          const chars = editor.getCharCoords();
          if (chars.length === 0) {
            dbgPrint("err", "No hay caracteres (elemento vacio o no es MathText)");
          } else {
            dbgPrint("info", `${chars.length} caracteres:`);
            for (const c of chars) {
              dbgPrint("data", `  [${c.idx}] '${c.char}' @ x=${c.x} y=${c.y} w=${c.w} h=${c.h}`);
            }
            const json = JSON.stringify(chars, null, 2);
            dbgPrint("data", "JSON:", json);
          }
          break;
        }

        case "elements":
        case "el": {
          const row = args[0] !== undefined ? parseInt(args[0]) : undefined;
          const elements = editor.getRowElements(row);
          if (elements.length === 0) {
            dbgPrint("err", "Sin elementos en esa fila");
          } else {
            dbgPrint("info", `${elements.length} elementos en fila ${row ?? '(actual)'}:`);
            for (const e of elements) {
              const cur = e.cursor ? " <<CURSOR>>" : "";
              const txt = e.text !== undefined ? ` "${e.text}"` : "";
              dbgPrint("data", `  [${e.row},${e.col}][${e.idx}] ${e.type}${txt} @ (${e.x},${e.y}) ${e.w}x${e.h}${cur}`);
            }
          }
          break;
        }

        case "rows": {
          const info = editor.getDebugInfo();
          for (let r = 0; r < info.totalRows; r++) {
            const els = editor.getRowElements(r);
            const texts = els.filter((e: any) => e.text !== undefined).map((e: any) => e.text).join(" | ");
            const mark = r === info.row ? " <<<" : "";
            dbgPrint("data", `  fila ${r}: ${els.length} elementos — ${texts}${mark}`);
          }
          break;
        }

        case "left":
        case "l": {
          const n = parseInt(args[0] || "1");
          for (let i = 0; i < n; i++) editor.moveCursorLeft();
          const info = editor.getDebugInfo();
          dbgPrint("ok", `Cursor: [${info.row},${info.col}] pos=${info.element?.cursorPosition ?? '?'}`);
          break;
        }

        case "right":
        case "r": {
          const n = parseInt(args[0] || "1");
          for (let i = 0; i < n; i++) editor.moveCursorRight();
          const info = editor.getDebugInfo();
          dbgPrint("ok", `Cursor: [${info.row},${info.col}] pos=${info.element?.cursorPosition ?? '?'}`);
          break;
        }

        case "up":
        case "u":
          editor.moveCursorUp();
          dbgPrint("ok", `Cursor: [${editor.getDebugInfo().row},${editor.getDebugInfo().col}]`);
          break;

        case "down":
        case "d":
          editor.moveCursorDown();
          dbgPrint("ok", `Cursor: [${editor.getDebugInfo().row},${editor.getDebugInfo().col}]`);
          break;

        case "goto": {
          const r = parseInt(args[0] ?? "-1");
          const c = parseInt(args[1] ?? "0");
          const p = args[2] !== undefined ? parseInt(args[2]) : undefined;
          const result = editor.moveCursorTo(r, c, p);
          dbgPrint(result.startsWith("OK") ? "ok" : "err", result);
          break;
        }

        case "click": {
          const cx = parseFloat(args[0] ?? "0");
          const cy = parseFloat(args[1] ?? "0");
          const result = editor.simulateClick(cx, cy);
          dbgPrint("ok", result);
          // Mostrar info del nuevo elemento
          const info = editor.getDebugInfo();
          if (info.element) {
            dbgPrint("info", `→ ${info.element.type} "${info.element.text ?? ''}" pos=${info.element.cursorPosition ?? '?'} @ (${info.element.x},${info.element.y})`);
          }
          break;
        }

        case "type": {
          const text = parts.slice(1).join(" ");
          if (!text) { dbgPrint("err", "Uso: type TEXTO"); break; }
          const result = editor.typeText(text);
          dbgPrint(result.startsWith("OK") ? "ok" : "err", result);
          break;
        }

        case "del": {
          const n = parseInt(args[0] || "1");
          const result = editor.deleteBack(n);
          dbgPrint(result.startsWith("OK") ? "ok" : "err", result);
          break;
        }

        case "text": {
          const info = editor.getDebugInfo();
          if (info.element?.text !== undefined) {
            dbgPrint("ok", `Texto plano: "${info.element.text}"`);
            dbgPrint("ok", `Display:     "${info.element.displayText}"`);
            dbgPrint("info", `Pos: ${info.element.cursorPosition}/${info.element.textLength}`);
          } else {
            dbgPrint("err", "Elemento actual no tiene texto");
          }
          break;
        }

        case "all": {
          const code = editor.toHekatan();
          dbgPrint("ok", `${code.split('\n').length} lineas:`);
          for (const line of code.split('\n')) {
            dbgPrint("data", "  " + line);
          }
          dbgPrint("data", "", code);
          break;
        }

        case "clicklog": {
          const onoff = (args[0] || "").toLowerCase();
          if (onoff === "on") {
            editor.onDebugClick = (info) => {
              dbgPrint("info", `CLICK mouse=(${info.mouseX},${info.mouseY}) content=(${info.contentX},${info.contentY})`);
              dbgPrint("info", `  hitTest → row=${info.foundRow} col=${info.foundCol} type=${info.elementType} text="${info.elementText}"`);
              dbgPrint("info", `  cursor → row=${info.cursorRow} element="${info.cursorElement}"`);
            };
            dbgPrint("ok", "Click logging ACTIVADO — haz click en el canvas");
          } else if (onoff === "off") {
            editor.onDebugClick = null;
            dbgPrint("ok", "Click logging DESACTIVADO");
          } else {
            dbgPrint("err", "Uso: clicklog on|off");
          }
          break;
        }

        case "bounds": {
          const rowArg = args[0] ? parseInt(args[0]) : -1;
          const allBounds = editor.getElementBounds();
          const rows = rowArg >= 0 ? allBounds.filter(r => r.row === rowArg) : allBounds;
          for (const r of rows) {
            dbgPrint("info", `Row ${r.row}:`);
            for (const el of r.elements) {
              dbgPrint("data", `  ${el.type} "${el.text}" @ (${el.x},${el.y}) ${el.w}x${el.h}`);
            }
          }
          if (rows.length === 0) dbgPrint("err", `No se encontro row ${rowArg}`);
          break;
        }

        case "eval":
          editor.render();
          dbgPrint("ok", "Evaluacion forzada");
          break;

        case "render":
          editor.render();
          dbgPrint("ok", "Canvas re-renderizado");
          break;

        case "focus":
          mathCanvasEl.focus();
          dbgPrint("ok", `Focus + cursor timer: ${editor.getDebugInfo().cursorTimer ? 'ON' : 'OFF'}`);
          break;

        case "clear":
        case "cls":
          debugOutput.innerHTML = "";
          break;

        // ─── Insertar estructuras matemáticas ───

        case "line": {
          const text = parts.slice(1).join(" ");
          if (!text) { dbgPrint("err", "Uso: line TEXTO (inserta nueva fila)"); break; }
          const result = editor.insertLine(text);
          dbgPrint(result.startsWith("OK") ? "ok" : "err", result);
          break;
        }

        case "frac": {
          const num = args[0] || "";
          const den = args[1] || "";
          dbgPrint("ok", editor.insertFraction(num, den));
          break;
        }

        case "pow":
        case "power": {
          const base = args[0] || "";
          const exp = args[1] || "";
          dbgPrint("ok", editor.insertPower(base, exp));
          break;
        }

        case "sub":
        case "subscript": {
          const base = args[0] || "x";
          const sub = args[1] || "i";
          dbgPrint("ok", editor.insertSubscript(base, sub));
          break;
        }

        case "sqrt":
        case "root": {
          const rad = args[0] || "";
          dbgPrint("ok", editor.insertRoot(rad));
          break;
        }

        case "integral":
        case "int": {
          const lo = args[0] || "0";
          const hi = args[1] || "1";
          const body = args[2] || "";
          dbgPrint("ok", editor.insertIntegral(lo, hi, body));
          break;
        }

        case "deriv":
        case "derivative": {
          const fn = args[0] || "f";
          const vr = args[1] || "x";
          dbgPrint("ok", editor.insertDerivative(fn, vr));
          break;
        }

        case "matrix":
        case "mat": {
          const rows = parseInt(args[0] || "2");
          const cols = parseInt(args[1] || "2");
          dbgPrint("ok", editor.insertMatrix(rows, cols));
          break;
        }

        case "vector":
        case "vec": {
          const vals = args.length > 0 ? args : ["0", "0", "0"];
          dbgPrint("ok", editor.insertVector(vals));
          break;
        }

        // ─── Test completo automatizado ───
        case "test": {
          dbgPrint("info", "=== TEST COMPLETO DEL MATHEDITOR ===");
          dbgPrint("info", "");

          // 1. Insertar ecuación simple
          dbgPrint("info", "--- 1. Insertar ecuación: x = 5 ---");
          const r1 = editor.insertLine("x = 5");
          dbgPrint("ok", r1);
          dbgPrint("ok", `  → info: ${JSON.stringify(editor.getDebugInfo().element)}`);

          // 2. Insertar ecuación con operaciones
          dbgPrint("info", "--- 2. Insertar: y = x^2 + 3*x - 1 ---");
          const r2 = editor.insertLine("y = x^2 + 3*x - 1");
          dbgPrint("ok", r2);

          // 3. Insertar raíz cuadrada
          dbgPrint("info", "--- 3. Insertar: z = sqrt(x^2 + y^2) ---");
          const r3 = editor.insertLine("z = sqrt(x^2 + y^2)");
          dbgPrint("ok", r3);

          // 4. Navegar y editar
          dbgPrint("info", "--- 4. Navegar arriba 2 filas (a 'y = x^2...') ---");
          editor.moveCursorUp();
          editor.moveCursorUp();
          const infoY = editor.getDebugInfo();
          dbgPrint("ok", `  En fila ${infoY.row}: "${infoY.element?.text}"`);

          // 5. Ir al final y eliminar
          dbgPrint("info", "--- 5. Ir al final y borrar 2 chars ---");
          editor.moveCursorRight();
          editor.moveCursorRight();
          editor.moveCursorRight();
          // Navigate to last text element
          const rowEls = editor.getRowElements();
          dbgPrint("data", `  Elementos en fila: ${rowEls.map((e: any) => e.type + ':"' + (e.text ?? '') + '"').join(', ')}`);

          // 6. Insertar nueva línea con fracción
          dbgPrint("info", "--- 6. Insertar ecuación con fracción: a/b ---");
          const r6 = editor.insertLine("w = a/b + c");
          dbgPrint("ok", r6);
          const els6 = editor.getRowElements();
          dbgPrint("data", `  Elementos: ${els6.map((e: any) => e.type).join(', ')}`);

          // 7. Insertar línea vacía + matriz
          dbgPrint("info", "--- 7. Insertar matriz 2x2 ---");
          editor.insertLine("M = ");
          const r7 = editor.insertMatrix(2, 2);
          dbgPrint("ok", r7);

          // 8. Insertar vector
          dbgPrint("info", "--- 8. Insertar vector ---");
          editor.insertLine("v = ");
          const r8 = editor.insertVector(["1", "2", "3"]);
          dbgPrint("ok", r8);

          // 9. Verificar que todo el contenido se serializa
          dbgPrint("info", "--- 9. Verificar serialización ---");
          const code = editor.toHekatan();
          const lines = code.split('\n');
          dbgPrint("ok", `Total: ${lines.length} líneas`);

          // 10. Forzar evaluación
          dbgPrint("info", "--- 10. Evaluación ---");
          editor.render();
          dbgPrint("ok", "Render completado");

          dbgPrint("info", "");
          dbgPrint("info", "=== TEST COMPLETO FINALIZADO ===");
          break;
        }

        // ─── Comandos de ventana ───
        case "new":
        case "blank": {
          editor.loadFromText("");
          codeInput.value = "";
          exampleSelect.value = "";
          if (currentMode === "canvas") {
            mathCanvasEl.focus();
          }
          runCode();
          dbgPrint("ok", "Nueva hoja en blanco");
          break;
        }

        case "examples":
        case "list": {
          dbgPrint("info", "Ejemplos disponibles:");
          for (const [key, ex] of Object.entries(EXAMPLES)) {
            const mark = exampleSelect.value === key ? " <<<" : "";
            dbgPrint("data", `  ${key} — ${ex.name}${mark}`);
          }
          break;
        }

        case "load": {
          const name = args[0];
          if (!name) {
            dbgPrint("err", "Uso: load NOMBRE (usa 'examples' para ver lista)");
            break;
          }
          const ex = EXAMPLES[name];
          if (!ex) {
            // Try partial match
            const match = Object.keys(EXAMPLES).find(k => k.toLowerCase().startsWith(name.toLowerCase()));
            if (match) {
              const mex = EXAMPLES[match];
              exampleSelect.value = match;
              codeInput.value = mex.code;
              editor.loadFromText(mex.code);
              runCode();
              if (currentMode === "canvas") mathCanvasEl.focus();
              dbgPrint("ok", `Cargado: ${match} — ${mex.name}`);
            } else {
              dbgPrint("err", `Ejemplo '${name}' no encontrado. Usa 'examples' para ver lista.`);
            }
            break;
          }
          exampleSelect.value = name;
          codeInput.value = ex.code;
          editor.loadFromText(ex.code);
          runCode();
          if (currentMode === "canvas") mathCanvasEl.focus();
          dbgPrint("ok", `Cargado: ${name} — ${ex.name}`);
          break;
        }

        case "mode": {
          const m = (args[0] || "").toLowerCase();
          if (m === "canvas" || m === "c") {
            setMode("canvas");
            dbgPrint("ok", "Modo: MathCanvas");
          } else if (m === "code" || m === "t") {
            setMode("code");
            dbgPrint("ok", "Modo: Code");
          } else {
            dbgPrint("info", `Modo actual: ${currentMode}`);
            dbgPrint("help", "Uso: mode canvas|code");
          }
          break;
        }

        case "preset": {
          const t = (args[0] || "").toLowerCase();
          const presetNames = Object.keys(PRESETS);
          const shortcuts: Record<string, string> = { c: "classic", b: "black", d: "dark", h: "hekatan", l: "latex", g: "gabriola", m: "mathcad" };
          const resolved = shortcuts[t] || t;
          if (PRESETS[resolved]) {
            presetSelect.value = resolved;
            presetSelect.dispatchEvent(new Event("change"));
            dbgPrint("ok", `Preset: ${resolved}`);
          } else if (t === "cycle" || t === "test") {
            const delay = parseInt(args[1] || "2", 10) * 1000;
            dbgPrint("info", `Ciclando presets cada ${delay / 1000}s...`);
            let i = 0;
            const step = () => {
              if (i >= presetNames.length) { dbgPrint("ok", "Ciclo completado"); return; }
              presetSelect.value = presetNames[i];
              presetSelect.dispatchEvent(new Event("change"));
              dbgPrint("ok", `[${i + 1}/${presetNames.length}] Preset: ${presetNames[i]}`);
              i++;
              setTimeout(step, delay);
            };
            step();
          } else if (t === "next" || t === "n") {
            const cur = presetNames.indexOf(presetSelect.value);
            const next = (cur + 1) % presetNames.length;
            presetSelect.value = presetNames[next];
            presetSelect.dispatchEvent(new Event("change"));
            dbgPrint("ok", `Preset: ${presetNames[next]}`);
          } else if (t === "prev" || t === "p") {
            const cur = presetNames.indexOf(presetSelect.value);
            const prev = (cur - 1 + presetNames.length) % presetNames.length;
            presetSelect.value = presetNames[prev];
            presetSelect.dispatchEvent(new Event("change"));
            dbgPrint("ok", `Preset: ${presetNames[prev]}`);
          } else {
            dbgPrint("info", `Preset actual: ${presetSelect.value}`);
            dbgPrint("help", "Uso: preset hekatan|latex|gabriola|mathcad|classic|black|dark|next|prev|cycle [seg]");
          }
          break;
        }

        case "theme": {
          // Legacy alias for preset
          const t = (args[0] || "").toLowerCase();
          const shortcuts: Record<string, string> = { c: "classic", b: "black", d: "dark", h: "hekatan", l: "latex", g: "gabriola", m: "mathcad" };
          const resolved = shortcuts[t] || t;
          if (PRESETS[resolved]) {
            presetSelect.value = resolved;
            presetSelect.dispatchEvent(new Event("change"));
            dbgPrint("ok", `Preset: ${resolved}`);
          } else {
            dbgPrint("info", `Preset actual: ${presetSelect.value}`);
            dbgPrint("help", "Uso: preset hekatan|latex|gabriola|mathcad|classic|black|dark");
          }
          break;
        }

        case "fonttext": {
          const v = (args[0] || "").toLowerCase();
          const opts = ["segoeui", "georgia", "tahoma", "cambria", "times"];
          if (opts.includes(v)) {
            fontTextSelect.value = v;
            fontTextSelect.dispatchEvent(new Event("change"));
            dbgPrint("ok", `Fuente texto: ${v}`);
          } else {
            dbgPrint("info", `Fuente texto actual: ${fontTextSelect.value}`);
            dbgPrint("help", "Uso: fonttext segoeui|georgia|tahoma|cambria|times");
          }
          break;
        }

        case "fontexpr": {
          const v = (args[0] || "").toLowerCase();
          const opts = ["stix", "cambria", "gabriola", "georgiapro", "century"];
          if (opts.includes(v)) {
            fontExprSelect.value = v;
            fontExprSelect.dispatchEvent(new Event("change"));
            dbgPrint("ok", `Fuente expresiones: ${v}`);
          } else {
            dbgPrint("info", `Fuente expresiones actual: ${fontExprSelect.value}`);
            dbgPrint("help", "Uso: fontexpr stix|cambria|gabriola|georgiapro|century");
          }
          break;
        }

        case "color": {
          const v = (args[0] || "").toLowerCase();
          const opts = ["classic", "black", "dark"];
          const shortcuts: Record<string, string> = { c: "classic", b: "black", d: "dark" };
          const resolved = shortcuts[v] || v;
          if (opts.includes(resolved)) {
            colorModeSelect.value = resolved;
            colorModeSelect.dispatchEvent(new Event("change"));
            dbgPrint("ok", `Modo color: ${resolved}`);
          } else {
            dbgPrint("info", `Modo color actual: ${colorModeSelect.value}`);
            dbgPrint("help", "Uso: color classic|black|dark");
          }
          break;
        }

        case "autorun": {
          const v = (args[0] || "").toLowerCase();
          if (v === "on" || v === "1") {
            chkAutoRun.checked = true;
            chkAutoRun.dispatchEvent(new Event("change"));
            dbgPrint("ok", "AutoRun: ON");
          } else if (v === "off" || v === "0") {
            chkAutoRun.checked = false;
            chkAutoRun.dispatchEvent(new Event("change"));
            dbgPrint("ok", "AutoRun: OFF");
          } else {
            dbgPrint("info", `AutoRun: ${chkAutoRun.checked ? "ON" : "OFF"}`);
          }
          break;
        }

        case "run": {
          if (currentMode === "canvas") {
            codeInput.value = editor.toHekatan();
          }
          runCode();
          dbgPrint("ok", "Codigo ejecutado");
          break;
        }

        default:
          dbgPrint("err", `Comando desconocido: '${cmd}'. Escribe 'help' para ver comandos.`);
      }
    } catch (err: any) {
      dbgPrint("err", `Error: ${err.message}`);
    }
  }

  // Input handlers
  debugInput.addEventListener("keydown", (e) => {
    if (e.key === "Enter") {
      execDebugCmd(debugInput.value);
      debugInput.value = "";
      e.preventDefault();
    } else if (e.key === "ArrowUp") {
      if (histIdx > 0) {
        histIdx--;
        debugInput.value = cmdHistory[histIdx];
      }
      e.preventDefault();
    } else if (e.key === "ArrowDown") {
      if (histIdx < cmdHistory.length - 1) {
        histIdx++;
        debugInput.value = cmdHistory[histIdx];
      } else {
        histIdx = cmdHistory.length;
        debugInput.value = "";
      }
      e.preventDefault();
    } else if (e.key === "Escape") {
      toggleDebug();
    }
    e.stopPropagation(); // No enviar keys al canvas/textarea
  });
  debugInput.addEventListener("keypress", (e) => e.stopPropagation());
  debugInput.addEventListener("keyup", (e) => e.stopPropagation());

  // Expose to window for console access
  (window as any).__dbg = execDebugCmd;
  (window as any).__editor = editor;
}

