function renderKeypad(tabName: string) {
  const kc = document.getElementById("keypadContent");
  if (!kc) return;
  kc.innerHTML = "";

  if (tabName === "matrices") {
    // Render sectioned layout for matrices
    for (const section of MATRICES_SECTIONS) {
      const hdr = document.createElement("span");
      hdr.className = "keypad-section-hdr";
      hdr.textContent = section.header;
      kc.appendChild(hdr);
      for (const item of section.items) {
        const btn = document.createElement("button");
        btn.className = "key-btn wide";
        btn.textContent = item.label;
        btn.dataset.insert = item.insert;
        btn.title = item.tip;
        kc.appendChild(btn);
      }
    }
    return;
  }

  const items = KEYPAD_DATA[tabName] || [];
  for (const item of items) {
    const btn = document.createElement("button");
    btn.className = item.label.length > 3 ? "key-btn wide" : "key-btn";
    btn.textContent = item.label;
    btn.dataset.insert = item.insert;
    btn.title = item.insert.replace(/\\n/g, "\u21B5");
    kc.appendChild(btn);
  }
}

document.querySelectorAll<HTMLButtonElement>(".keypad-tab").forEach(tab => {
  tab.addEventListener("click", () => {
    document.querySelectorAll(".keypad-tab").forEach(t => t.classList.remove("active"));
    tab.classList.add("active");
    renderKeypad(tab.dataset.tab!);
  });
});
renderKeypad("greek");

// ─── Insert helpers ──────────────────────────────────────
function insertText(text: string) {
  const t = text.replace(/\\n/g, "\n");
  const start = codeInput.selectionStart;
  const end = codeInput.selectionEnd;
  codeInput.value = codeInput.value.substring(0, start) + t + codeInput.value.substring(end);
  codeInput.selectionStart = codeInput.selectionEnd = start + t.length;
  codeInput.focus();
  updateSyntax();
  runCode();
}

// Wire up all data-insert buttons (menu + toolbar + keypad)
document.addEventListener("click", (e) => {
  const btn = (e.target as HTMLElement).closest("[data-insert]") as HTMLElement | null;
  if (btn) {
    insertText(btn.dataset.insert!);
  }
});

// ─── Menu Bar Actions ─────────────────────────────────────
document.querySelectorAll<HTMLButtonElement>(".menu-dropdown button[data-action]").forEach(btn => {
  btn.addEventListener("click", () => {
    const action = btn.dataset.action;
    switch (action) {
      case "new":
        codeInput.value = "";
        editor.loadFromText("");
        updateSyntax();
        runCode();
        break;
      case "open": {
        const inp = document.createElement("input");
        inp.type = "file";
        inp.accept = ".hcalc,.txt";
        inp.onchange = () => {
          const f = inp.files?.[0];
          if (!f) return;
          f.text().then(t => {
            codeInput.value = t;
            editor.loadFromText(t);
            updateSyntax();
            runCode();
          });
        };
        inp.click();
        break;
      }
      case "save":
      case "saveas": {
        const blob = new Blob([codeInput.value], { type: "text/plain" });
        const a = document.createElement("a");
        a.href = URL.createObjectURL(blob);
        a.download = "documento.hcalc";
        a.click();
        URL.revokeObjectURL(a.href);
        break;
      }
      case "export-html": {
        const outputEl = document.getElementById("output")!;
        const html = `<!DOCTYPE html>
<html lang="es"><head><meta charset="UTF-8"><title>Hekatan Output</title>
<style>body{font-family:'Segoe UI',sans-serif;margin:20px;}</style>
</head><body>${outputEl.innerHTML}</body></html>`;
        const blob = new Blob([html], { type: "text/html" });
        const a = document.createElement("a");
        a.href = URL.createObjectURL(blob);
        a.download = "output.html";
        a.click();
        URL.revokeObjectURL(a.href);
        break;
      }
      case "export-pdf":
      case "print": {
        // Export PDF: print ONLY the output panel content
        const outputEl = document.getElementById("output")!;
        const printWin = window.open("", "_blank")!;
        // Collect all stylesheets from current page
        const styles = Array.from(document.querySelectorAll("style, link[rel='stylesheet']"))
          .map(el => el.outerHTML).join("\n");
        printWin.document.write(`<!DOCTYPE html>
<html lang="es"><head><meta charset="UTF-8"><title>Hekatan - Export PDF</title>
${styles}
<style>
  @media print {
    @page { size: A4; margin: 10mm; }
    body { margin: 0; padding: 0; background: white; }
    .page { margin: 0 auto; box-shadow: none; }
  }
  body { background: white; margin: 0; padding: 0; }
  .output-content { all: unset; }
</style>
</head><body>${outputEl.innerHTML}</body></html>`);
        printWin.document.close();
        // Give images/canvases time to load before printing
        setTimeout(() => {
          printWin.focus();
          printWin.print();
        }, 800);
        break;
      }
      case "undo":
        document.execCommand("undo");
        break;
      case "redo":
        document.execCommand("redo");
        break;
      case "selectall":
        codeInput.select();
        break;
      case "find":
        // Trigger find & replace (Ctrl+F)
        (document.querySelector("#codeInput") as HTMLTextAreaElement)?.focus();
        break;
      case "help-ref":
        window.open("/help.html", "_blank");
        break;
      case "help-about": {
        const overlay = document.createElement("div");
        overlay.style.cssText = `position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.55);display:flex;align-items:center;justify-content:center;z-index:9999;`;
        overlay.innerHTML = `
          <div style="background:#fff;border-radius:10px;padding:32px 44px;text-align:center;box-shadow:0 8px 32px rgba(0,0,0,0.3);max-width:440px;">
            <div style="font-size:36px;margin-bottom:8px;color:#00D4AA;">&#9773;</div>
            <h2 style="margin:0 0 6px;font-size:18px;color:#00D4AA;">Hekatan Math Editor</h2>
            <p style="margin:0 0 4px;color:#D4AF37;font-size:11px;font-style:italic;">The Magic of Calculation for Engineers</p>
            <p style="margin:8px 0;color:#666;font-size:12px;line-height:1.5;">
              Motor: <b>math.js</b> + <b>Eigen C++/WebAssembly</b><br>
              Ecuaciones • Matrices • CAD 2D • Three.js 3D<br>
              Funciones MATLAB-like • Documentos tipo libro
            </p>
            <p style="margin:8px 0 16px;color:#999;font-size:10px;">Version 1.0 &mdash; 2026</p>
            <button style="background:#00D4AA;color:#fff;border:none;border-radius:6px;padding:8px 28px;font-size:14px;cursor:pointer;" id="_aboutClose">Cerrar</button>
          </div>
        `;
        document.body.appendChild(overlay);
        overlay.querySelector("#_aboutClose")!.addEventListener("click", () => overlay.remove());
        overlay.addEventListener("click", (e) => { if (e.target === overlay) overlay.remove(); });
        break;
      }
    }
  });
});

